export enum ClassType {
  OneOnOne = 'One-on-One',
  Group = 'One-on-Two'
}

export enum AttendanceStatus {
  Present = 'Present',
  Absent = 'Absent',
  Late = 'Late',
  Cancelled = 'Cancelled'
}

export interface Student {
  id: string;
  name: string;
  classType: ClassType;
  email?: string;
  parentName?: string;
  notes: string;
  balance: number; // Positive means they owe, negative means credit
  joinedDate: string;
}

export interface Session {
  id: string;
  studentIds: string[];
  date: string; // ISO date string
  durationMinutes: number;
  status: AttendanceStatus;
  topic: string;
  notes: string;
  price: number;
}

export interface Payment {
  id: string;
  studentId: string;
  amount: number;
  date: string;
  method: string;
}

export interface TabItem {
  id: string;
  label: string;
  icon: React.ElementType;
}

