import { GoogleGenAI } from "@google/genai";
import { Student, Session } from "../types";

const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API Key not found in environment variables.");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const generateStudentReport = async (student: Student, recentSessions: Session[]): Promise<string> => {
  const ai = getAIClient();
  if (!ai) return "API Key missing. Cannot generate report.";

  const sessionSummary = recentSessions.map(s => 
    `- Date: ${new Date(s.date).toLocaleDateString()}, Topic: ${s.topic}, Status: ${s.status}, Notes: ${s.notes}`
  ).join('\n');

  const prompt = `
    You are a professional and encouraging English tutor assistant.
    Write a short progress report email to the parent of ${student.name} (${student.parentName || 'Parent'}).

    Student Details:
    - Class Type: ${student.classType}
    - Recent Performance Notes: ${student.notes}

    Recent Sessions:
    ${sessionSummary}

    The email should be professional, highlight strengths, identify one area for improvement, and encourage the student.
    Keep it under 200 words.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Could not generate report.";
  } catch (error) {
    console.error("Error generating report:", error);
    return "Error contacting AI service. Please try again later.";
  }
};

export const generateLessonPlan = async (topic: string, studentNames: string[], duration: number): Promise<string> => {
  const ai = getAIClient();
  if (!ai) return "API Key missing.";

  const prompt = `
    Create a simple, engaging English lesson plan for:
    - Topic: ${topic}
    - Students: ${studentNames.join(', ')}
    - Duration: ${duration} minutes

    Include:
    1. Warm-up activity (5 min)
    2. Main Concept (10 min)
    3. Practice Activity (Interactive)
    4. Cool down / Review

    Format the output in clear Markdown.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Could not generate lesson plan.";
  } catch (error) {
    console.error("Error generating lesson plan:", error);
    return "Error contacting AI service.";
  }
};

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { Users, DollarSign, CalendarCheck, TrendingUp } from 'lucide-react';
import { Student, Session, Payment, AttendanceStatus } from '../types';

interface DashboardProps {
  students: Student[];
  sessions: Session[];
  payments: Payment[];
}

const Dashboard: React.FC<DashboardProps> = ({ students, sessions, payments }) => {
  // Calculate total revenue
  const totalRevenue = payments.reduce((sum, p) => sum + p.amount, 0);

  // Calculate attendance rate
  const totalSessions = sessions.length;
  const attendedSessions = sessions.filter(s => s.status === AttendanceStatus.Present).length;
  const attendanceRate = totalSessions > 0 ? Math.round((attendedSessions / totalSessions) * 100) : 0;

  // Active students
  const activeStudents = students.length;

  // Outstanding Balance (Total owed by all students)
  const totalOutstanding = students.reduce((sum, s) => sum + (s.balance > 0 ? s.balance : 0), 0);

  // Prepare chart data (Sessions per day for the last 7 days logic simplified for demo)
  // Group sessions by date
  const sessionData = sessions.reduce((acc, session) => {
    const date = new Date(session.date).toLocaleDateString('en-US', { weekday: 'short' });
    const existing = acc.find(item => item.name === date);
    if (existing) {
      existing.count += 1;
    } else {
      acc.push({ name: date, count: 1 });
    }
    return acc;
  }, [] as { name: string; count: number }[]);

  // Sort vaguely by date (in a real app, use proper date manipulation)
  // For this mock, let's just reverse to show latest first or keep as is if chronological

  const StatCard = ({ title, value, sub, icon: Icon, color }: any) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
      <div>
        <p className="text-sm font-medium text-slate-500">{title}</p>
        <h3 className="text-2xl font-bold text-slate-800 mt-1">{value}</h3>
        {sub && <p className="text-xs text-slate-400 mt-1">{sub}</p>}
      </div>
      <div className={`p-3 rounded-full ${color} bg-opacity-10`}>
        <Icon className={`w-6 h-6 ${color.replace('bg-', 'text-')}`} />
      </div>
    </div>
  );

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard 
          title="Total Revenue" 
          value={`$${totalRevenue.toLocaleString()}`} 
          sub="All time earnings"
          icon={DollarSign} 
          color="bg-emerald-500" 
        />
        <StatCard 
          title="Active Students" 
          value={activeStudents} 
          sub="Currently enrolled"
          icon={Users} 
          color="bg-blue-500" 
        />
        <StatCard 
          title="Attendance Rate" 
          value={`${attendanceRate}%`} 
          sub="Last 30 days"
          icon={CalendarCheck} 
          color="bg-violet-500" 
        />
        <StatCard 
          title="Outstanding" 
          value={`$${totalOutstanding}`} 
          sub="Pending payments"
          icon={TrendingUp} 
          color="bg-rose-500" 
        />
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 h-96">
        <h3 className="text-lg font-semibold text-slate-800 mb-6">Weekly Sessions Overview</h3>
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={sessionData}>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
            <XAxis dataKey="name" tick={{fill: '#64748b'}} axisLine={false} tickLine={false} />
            <YAxis tick={{fill: '#64748b'}} axisLine={false} tickLine={false} />
            <Tooltip 
              cursor={{fill: '#f8fafc'}}
              contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
            />
            <Bar dataKey="count" radius={[4, 4, 0, 0]}>
              {sessionData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill="#6366f1" />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Student, ClassType } from '../types';
import { Search, Plus, User, MoreHorizontal, Sparkles } from 'lucide-react';

interface StudentListProps {
  students: Student[];
  onAddStudent: (student: Omit<Student, 'id' | 'joinedDate'>) => void;
  onSelectStudent: (student: Student) => void;
}

const StudentList: React.FC<StudentListProps> = ({ students, onAddStudent, onSelectStudent }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [newStudent, setNewStudent] = useState({
    name: '',
    parentName: '',
    classType: ClassType.OneOnOne,
    notes: '',
    balance: 0,
  });

  const filteredStudents = students.filter(s => 
    s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.parentName?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAddStudent(newStudent);
    setIsAdding(false);
    setNewStudent({ name: '', parentName: '', classType: ClassType.OneOnOne, notes: '', balance: 0 });
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="relative w-full sm:w-64">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400 w-4 h-4" />
          <input
            type="text"
            placeholder="Search students..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-sm"
          />
        </div>
        <button
          onClick={() => setIsAdding(true)}
          className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors"
        >
          <Plus className="w-4 h-4" />
          Add Student
        </button>
      </div>

      {isAdding && (
        <div className="bg-white p-6 rounded-xl border border-indigo-100 shadow-sm animate-in fade-in slide-in-from-top-4">
          <h3 className="font-semibold text-lg mb-4">New Student</h3>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input
              required
              placeholder="Student Name"
              value={newStudent.name}
              onChange={e => setNewStudent({...newStudent, name: e.target.value})}
              className="p-2 border rounded-md"
            />
            <input
              placeholder="Parent Name"
              value={newStudent.parentName}
              onChange={e => setNewStudent({...newStudent, parentName: e.target.value})}
              className="p-2 border rounded-md"
            />
            <select
              value={newStudent.classType}
              onChange={e => setNewStudent({...newStudent, classType: e.target.value as ClassType})}
              className="p-2 border rounded-md"
            >
              <option value={ClassType.OneOnOne}>One-on-One</option>
              <option value={ClassType.Group}>One-on-Two (Group)</option>
            </select>
            <input
              type="number"
              placeholder="Initial Balance (Negative = Credit)"
              value={newStudent.balance}
              onChange={e => setNewStudent({...newStudent, balance: parseFloat(e.target.value)})}
              className="p-2 border rounded-md"
            />
            <textarea
              placeholder="Notes..."
              value={newStudent.notes}
              onChange={e => setNewStudent({...newStudent, notes: e.target.value})}
              className="p-2 border rounded-md md:col-span-2"
              rows={2}
            />
            <div className="md:col-span-2 flex justify-end gap-2">
              <button 
                type="button" 
                onClick={() => setIsAdding(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-50 rounded-md"
              >
                Cancel
              </button>
              <button 
                type="submit"
                className="px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-700"
              >
                Save Student
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredStudents.map(student => (
          <div 
            key={student.id} 
            onClick={() => onSelectStudent(student)}
            className="group bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md hover:border-indigo-200 transition-all cursor-pointer"
          >
            <div className="flex justify-between items-start mb-3">
              <div className="p-2 bg-slate-100 rounded-full group-hover:bg-indigo-50 transition-colors">
                <User className="w-5 h-5 text-slate-600 group-hover:text-indigo-600" />
              </div>
              <span className={`text-xs px-2 py-1 rounded-full ${student.classType === ClassType.OneOnOne ? 'bg-blue-100 text-blue-700' : 'bg-orange-100 text-orange-700'}`}>
                {student.classType}
              </span>
            </div>
            <h3 className="font-semibold text-slate-800">{student.name}</h3>
            <p className="text-sm text-slate-500 mb-4">{student.parentName || 'No parent listed'}</p>

            <div className="flex items-center justify-between pt-4 border-t border-slate-50">
              <div className="text-xs">
                <p className="text-slate-400">Balance</p>
                <p className={`font-medium ${student.balance > 0 ? 'text-red-500' : 'text-emerald-600'}`}>
                  {student.balance > 0 ? `Owes $${student.balance}` : student.balance < 0 ? `Credit $${Math.abs(student.balance)}` : 'Settled'}
                </p>
              </div>
              <MoreHorizontal className="w-4 h-4 text-slate-300" />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default StudentList;

import React, { useState } from 'react';
import { Session, Student, AttendanceStatus, ClassType } from '../types';
import { Calendar, Clock, CheckCircle, XCircle, AlertCircle, Sparkles } from 'lucide-react';
import { generateLessonPlan } from '../services/geminiService';

interface SessionLogProps {
  sessions: Session[];
  students: Student[];
  onAddSession: (session: Omit<Session, 'id'>) => void;
}

const SessionLog: React.FC<SessionLogProps> = ({ sessions, students, onAddSession }) => {
  const [isLogging, setIsLogging] = useState(false);
  const [selectedStudents, setSelectedStudents] = useState<string[]>([]);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [time, setTime] = useState('14:00');
  const [topic, setTopic] = useState('');
  const [status, setStatus] = useState<AttendanceStatus>(AttendanceStatus.Present);
  const [notes, setNotes] = useState('');

  // AI State
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [generatedPlan, setGeneratedPlan] = useState('');

  const handleStudentToggle = (id: string) => {
    if (selectedStudents.includes(id)) {
      setSelectedStudents(selectedStudents.filter(s => s !== id));
    } else {
      if (selectedStudents.length >= 2) return; // Limit to 2 for simplicity based on req
      setSelectedStudents([...selectedStudents, id]);
    }
  };

  const handleGeneratePlan = async () => {
    if (!topic || selectedStudents.length === 0) return;
    setIsGeneratingPlan(true);
    const studentNames = students.filter(s => selectedStudents.includes(s.id)).map(s => s.name);
    const plan = await generateLessonPlan(topic, studentNames, 60);
    setGeneratedPlan(plan);
    setNotes(prev => prev + (prev ? '\n\n' : '') + "Lesson Plan: " + topic);
    setIsGeneratingPlan(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedStudents.length === 0) return;

    // Determine price based on class type of first student (simplified logic)
    const firstStudent = students.find(s => s.id === selectedStudents[0]);
    const price = firstStudent?.classType === ClassType.OneOnOne ? 40 : 30; // Mock prices

    onAddSession({
      studentIds: selectedStudents,
      date: `${date}T${time}:00`,
      durationMinutes: 60,
      status,
      topic,
      notes: generatedPlan ? `${notes}\n\n--- AI Plan ---\n${generatedPlan}` : notes,
      price: price * selectedStudents.length
    });

    setIsLogging(false);
    resetForm();
  };

  const resetForm = () => {
    setSelectedStudents([]);
    setTopic('');
    setNotes('');
    setGeneratedPlan('');
    setStatus(AttendanceStatus.Present);
  };

  const getStatusIcon = (status: AttendanceStatus) => {
    switch (status) {
      case AttendanceStatus.Present: return <CheckCircle className="w-4 h-4 text-emerald-500" />;
      case AttendanceStatus.Absent: return <XCircle className="w-4 h-4 text-red-500" />;
      case AttendanceStatus.Late: return <AlertCircle className="w-4 h-4 text-orange-500" />;
      default: return <Clock className="w-4 h-4 text-slate-400" />;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-slate-800">Session History</h2>
        <button
          onClick={() => setIsLogging(!isLogging)}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
        >
          <Calendar className="w-4 h-4" />
          Log Session
        </button>
      </div>

      {isLogging && (
        <div className="bg-white p-6 rounded-xl border border-indigo-100 shadow-sm animate-in fade-in slide-in-from-top-4">
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">Select Students (Max 2)</label>
              <div className="flex flex-wrap gap-2">
                {students.map(s => (
                  <button
                    key={s.id}
                    type="button"
                    onClick={() => handleStudentToggle(s.id)}
                    className={`px-3 py-1.5 rounded-full text-sm border transition-colors ${
                      selectedStudents.includes(s.id)
                        ? 'bg-indigo-100 border-indigo-300 text-indigo-700'
                        : 'bg-white border-slate-200 text-slate-600 hover:border-indigo-200'
                    }`}
                  >
                    {s.name} ({s.classType})
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <input
                type="date"
                value={date}
                onChange={e => setDate(e.target.value)}
                className="p-2 border rounded-md"
                required
              />
              <input
                type="time"
                value={time}
                onChange={e => setTime(e.target.value)}
                className="p-2 border rounded-md"
                required
              />
            </div>

            <div className="flex gap-4">
                <input
                    placeholder="Topic (e.g., Past Tense Verbs)"
                    value={topic}
                    onChange={e => setTopic(e.target.value)}
                    className="flex-1 p-2 border rounded-md"
                    required
                />
                <select
                    value={status}
                    onChange={e => setStatus(e.target.value as AttendanceStatus)}
                    className="p-2 border rounded-md w-32"
                >
                    {Object.values(AttendanceStatus).map(s => (
                        <option key={s} value={s}>{s}</option>
                    ))}
                </select>
            </div>

            <div className="relative">
                <textarea
                    placeholder="Session notes..."
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                    className="w-full p-2 border rounded-md"
                    rows={3}
                />
                <button
                    type="button"
                    disabled={!topic || selectedStudents.length === 0 || isGeneratingPlan}
                    onClick={handleGeneratePlan}
                    className="absolute bottom-2 right-2 text-xs flex items-center gap-1 bg-violet-100 text-violet-700 px-2 py-1 rounded-md hover:bg-violet-200 disabled:opacity-50"
                >
                    <Sparkles className="w-3 h-3" />
                    {isGeneratingPlan ? 'Generating...' : 'AI Plan'}
                </button>
            </div>

            {generatedPlan && (
                <div className="bg-violet-50 p-3 rounded-md text-xs text-slate-700 max-h-40 overflow-y-auto whitespace-pre-wrap border border-violet-100">
                    <h4 className="font-semibold text-violet-800 mb-1">Generated Plan Preview:</h4>
                    {generatedPlan}
                </div>
            )}

            <div className="flex justify-end gap-2 pt-2">
              <button 
                type="button" 
                onClick={() => { setIsLogging(false); resetForm(); }}
                className="px-4 py-2 text-slate-600 hover:bg-slate-50 rounded-md"
              >
                Cancel
              </button>
              <button 
                type="submit"
                className="px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-700"
              >
                Save Log
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="space-y-3">
        {sessions.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(session => (
          <div key={session.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="p-2 bg-slate-100 rounded-lg text-center min-w-[3.5rem]">
                <p className="text-xs font-bold text-slate-500 uppercase">{new Date(session.date).toLocaleDateString('en-US', { month: 'short' })}</p>
                <p className="text-lg font-bold text-slate-800">{new Date(session.date).getDate()}</p>
              </div>
              <div>
                <h4 className="font-semibold text-slate-800">{session.topic}</h4>
                <div className="flex items-center gap-2 text-sm text-slate-500">
                  <span>{session.studentIds.map(id => students.find(s => s.id === id)?.name).join(', ')}</span>
                  <span>•</span>
                  <span>{new Date(session.date).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })}</span>
                </div>
              </div>
            </div>
            <div className="flex items-center gap-2">
              {getStatusIcon(session.status)}
              <span className={`text-sm font-medium ${
                session.status === AttendanceStatus.Present ? 'text-emerald-600' : 
                session.status === AttendanceStatus.Absent ? 'text-red-600' : 'text-slate-600'
              }`}>
                {session.status}
              </span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

