interface StudentListProps {
  students: Student[];
  onAddStudent: (student: Omit<Student, 'id' | 'joinedDate'>) => void;
  onSelectStudent: (student: Student) => void;
}

const StudentList: React.FC<StudentListProps> = ({ students, onAddStudent, onSelectStudent }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [newStudent, setNewStudent] = useState({
    name: '',
    parentName: '',
    classTypes: [] as ClassType[],
    notes: '',
    balance: 0,
  });

  const filteredStudents = students.filter(s => 
    s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.parentName?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newStudent.classTypes.length === 0) {
        alert("Please select at least one class type.");
        return;
    }
    onAddStudent(newStudent);
    setIsAdding(false);
    setNewStudent({ name: '', parentName: '', classTypes: [], notes: '', balance: 0 });
  };

  const toggleClassType = (type: ClassType) => {
    if (newStudent.classTypes.includes(type)) {
        setNewStudent({ ...newStudent, classTypes: newStudent.classTypes.filter(t => t !== type) });
    } else {
        setNewStudent({ ...newStudent, classTypes: [...newStudent.classTypes, type] });
