};

export default StudentList;

import React, { useState } from 'react';
import { Session, Student, AttendanceStatus, ClassType } from '../types';
import { Calendar, Clock, CheckCircle, XCircle, AlertCircle, Sparkles } from 'lucide-react';
import { generateLessonPlan } from '../services/geminiService';
import { PRICE_1ON1, PRICE_GROUP } from '../constants';

interface SessionLogProps {
  sessions: Session[];
  students: Student[];
  onAddSession: (session: Omit<Session, 'id'>) => void;
}

const SessionLog: React.FC<SessionLogProps> = ({ sessions, students, onAddSession }) => {
  const [isLogging, setIsLogging] = useState(false);
  const [selectedStudents, setSelectedStudents] = useState<string[]>([]);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [time, setTime] = useState('14:00');
  const [topic, setTopic] = useState('');
  const [status, setStatus] = useState<AttendanceStatus>(AttendanceStatus.Present);
  const [sessionType, setSessionType] = useState<ClassType>(ClassType.OneOnOne);
  const [notes, setNotes] = useState('');

  // AI State
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [generatedPlan, setGeneratedPlan] = useState('');

  const handleStudentToggle = (id: string) => {
    if (selectedStudents.includes(id)) {
      setSelectedStudents(selectedStudents.filter(s => s !== id));
    } else {
      if (selectedStudents.length >= 2) return; // Limit to 2 for simplicity
      setSelectedStudents([...selectedStudents, id]);
    }
  };

  const handleGeneratePlan = async () => {
    if (!topic || selectedStudents.length === 0) return;
    setIsGeneratingPlan(true);
    const studentNames = students.filter(s => selectedStudents.includes(s.id)).map(s => s.name);
    const plan = await generateLessonPlan(topic, studentNames, 60);
    setGeneratedPlan(plan);
    setNotes(prev => prev + (prev ? '\n\n' : '') + "Lesson Plan: " + topic);
    setIsGeneratingPlan(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedStudents.length === 0) return;

    // Calculate total price based on session type and number of students
    const pricePerStudent = sessionType === ClassType.OneOnOne ? PRICE_1ON1 : PRICE_GROUP;
    const totalPrice = pricePerStudent * selectedStudents.length;

    onAddSession({
      studentIds: selectedStudents,
      date: `${date}T${time}:00`,
      durationMinutes: 60,
      status,
      type: sessionType,
      topic,
      notes: generatedPlan ? `${notes}\n\n--- AI Plan ---\n${generatedPlan}` : notes,
      price: totalPrice
    });

    setIsLogging(false);
    resetForm();
  };

  const resetForm = () => {
    setSelectedStudents([]);
    setTopic('');
    setNotes('');
    setGeneratedPlan('');
    setStatus(AttendanceStatus.Present);
    setSessionType(ClassType.OneOnOne);
  };

  const getStatusIcon = (status: AttendanceStatus) => {
    switch (status) {
      case AttendanceStatus.Present: return <CheckCircle className="w-4 h-4 text-emerald-500" />;
      case AttendanceStatus.Absent: return <XCircle className="w-4 h-4 text-red-500" />;
      case AttendanceStatus.Late: return <AlertCircle className="w-4 h-4 text-orange-500" />;
      default: return <Clock className="w-4 h-4 text-slate-400" />;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-slate-800">Session History</h2>
        <button
          onClick={() => setIsLogging(!isLogging)}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
        >
          <Calendar className="w-4 h-4" />
          Log Session
        </button>
      </div>

      {isLogging && (
        <div className="bg-white p-6 rounded-xl border border-indigo-100 shadow-sm animate-in fade-in slide-in-from-top-4">
          <form onSubmit={handleSubmit} className="space-y-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                     <label className="block text-sm font-medium text-slate-700 mb-2">Session Type</label>
                     <select
                        value={sessionType}
                        onChange={e => setSessionType(e.target.value as ClassType)}
                        className="w-full p-2 border rounded-md"
                    >
                        <option value={ClassType.OneOnOne}>One-on-One</option>
                        <option value={ClassType.Group}>One-on-Two (Group)</option>
                    </select>
                </div>
                <div>
                     <label className="block text-sm font-medium text-slate-700 mb-2">Select Students (Max 2)</label>
                     <div className="flex flex-wrap gap-2">
                        {students.map(s => (
                        <button
                            key={s.id}
                            type="button"
                            onClick={() => handleStudentToggle(s.id)}
                            className={`px-3 py-1.5 rounded-full text-sm border transition-colors ${
                            selectedStudents.includes(s.id)
                                ? 'bg-indigo-100 border-indigo-300 text-indigo-700'
                                : 'bg-white border-slate-200 text-slate-600 hover:border-indigo-200'
                            }`}
                        >
                            {s.name}
                        </button>
                        ))}
                     </div>
                </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <input
                type="date"
                value={date}
                onChange={e => setDate(e.target.value)}
                className="p-2 border rounded-md"
                required
              />
              <input
                type="time"
                value={time}
                onChange={e => setTime(e.target.value)}
                className="p-2 border rounded-md"
                required
              />
            </div>

            <div className="flex gap-4">
                <input
                    placeholder="Topic (e.g., Past Tense Verbs)"
                    value={topic}
                    onChange={e => setTopic(e.target.value)}
                    className="flex-1 p-2 border rounded-md"
                    required
                />
                <select
                    value={status}
                    onChange={e => setStatus(e.target.value as AttendanceStatus)}
                    className="p-2 border rounded-md w-32"
                >
                    {Object.values(AttendanceStatus).map(s => (
                        <option key={s} value={s}>{s}</option>
                    ))}
                </select>
            </div>

            <div className="relative">
                <textarea
                    placeholder="Session notes..."
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                    className="w-full p-2 border rounded-md"
                    rows={3}
                />
                <button
                    type="button"
                    disabled={!topic || selectedStudents.length === 0 || isGeneratingPlan}
                    onClick={handleGeneratePlan}
                    className="absolute bottom-2 right-2 text-xs flex items-center gap-1 bg-violet-100 text-violet-700 px-2 py-1 rounded-md hover:bg-violet-200 disabled:opacity-50"
                >
                    <Sparkles className="w-3 h-3" />
                    {isGeneratingPlan ? 'Generating...' : 'AI Plan'}
                </button>
            </div>

            {generatedPlan && (
                <div className="bg-violet-50 p-3 rounded-md text-xs text-slate-700 max-h-40 overflow-y-auto whitespace-pre-wrap border border-violet-100">
                    <h4 className="font-semibold text-violet-800 mb-1">Generated Plan Preview:</h4>
                    {generatedPlan}
                </div>
            )}

            <div className="flex justify-end gap-2 pt-2">
              <button 
                type="button" 
                onClick={() => { setIsLogging(false); resetForm(); }}
                className="px-4 py-2 text-slate-600 hover:bg-slate-50 rounded-md"
              >
                Cancel
              </button>
              <button 
                type="submit"
                className="px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-700"
              >
                Save Log
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="space-y-3">
        {sessions.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(session => (
          <div key={session.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="p-2 bg-slate-100 rounded-lg text-center min-w-[3.5rem]">
                <p className="text-xs font-bold text-slate-500 uppercase">{new Date(session.date).toLocaleDateString('en-US', { month: 'short' })}</p>
                <p className="text-lg font-bold text-slate-800">{new Date(session.date).getDate()}</p>
              </div>
              <div>
                <div className="flex items-center gap-2">
                    <h4 className="font-semibold text-slate-800">{session.topic}</h4>
                    <span className={`text-[10px] px-2 py-0.5 rounded-full border ${session.type === ClassType.OneOnOne ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-orange-50 text-orange-700 border-orange-100'}`}>
                        {session.type}
                    </span>
                </div>
                <div className="flex items-center gap-2 text-sm text-slate-500 mt-1">
                  <span>{session.studentIds.map(id => students.find(s => s.id === id)?.name).join(', ')}</span>
                  <span>•</span>
                  <span>{new Date(session.date).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })}</span>
                </div>
              </div>
            </div>
            <div className="flex items-center gap-2">
              {getStatusIcon(session.status)}
              <span className={`text-sm font-medium ${
                session.status === AttendanceStatus.Present ? 'text-emerald-600' : 
                session.status === AttendanceStatus.Absent ? 'text-red-600' : 'text-slate-600'
              }`}>
                {session.status}
              </span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default SessionLog;

import React, { useState } from 'react';
import { Student, Session, Payment, AttendanceStatus, ClassType } from '../types';
import { X, Mail, DollarSign, Calendar, Sparkles } from 'lucide-react';
import { generateStudentReport } from '../services/geminiService';

interface StudentDetailProps {
  student: Student;
  sessions: Session[];
  payments: Payment[];
  onClose: () => void;
  onUpdatePayment: (studentId: string, amount: number) => void;
}

const StudentDetail: React.FC<StudentDetailProps> = ({ student, sessions, payments, onClose, onUpdatePayment }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'history'>('overview');
  const [paymentAmount, setPaymentAmount] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  const studentSessions = sessions.filter(s => s.studentIds.includes(student.id));
  const attendedCount = studentSessions.filter(s => s.status === AttendanceStatus.Present).length;
  const attendanceRate = studentSessions.length ? Math.round((attendedCount / studentSessions.length) * 100) : 0;

  const handlePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!paymentAmount) return;
    onUpdatePayment(student.id, parseFloat(paymentAmount));
    setPaymentAmount('');
  };

  const handleGenerateReport = async () => {
    setIsGenerating(true);
    const report = await generateStudentReport(student, studentSessions.slice(0, 5)); // Send last 5 sessions
    setAiReport(report);
    setIsGenerating(false);
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex justify-end">
      <div className="w-full max-w-lg bg-slate-50 h-full shadow-2xl animate-in slide-in-from-right duration-300 flex flex-col">
