import React, { useState } from 'react';
import { Student, Session, Payment, AttendanceStatus, ClassType } from '../types';
import { X, Mail, DollarSign, Calendar, Sparkles } from 'lucide-react';
import { generateStudentReport } from '../services/geminiService';

interface StudentDetailProps {
  student: Student;
  sessions: Session[];
  payments: Payment[];
  onClose: () => void;
  onUpdatePayment: (studentId: string, amount: number) => void;
}

const StudentDetail: React.FC<StudentDetailProps> = ({ student, sessions, payments, onClose, onUpdatePayment }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'history'>('overview');
  const [paymentAmount, setPaymentAmount] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  const studentSessions = sessions.filter(s => s.studentIds.includes(student.id));
  const attendedCount = studentSessions.filter(s => s.status === AttendanceStatus.Present).length;
  const attendanceRate = studentSessions.length ? Math.round((attendedCount / studentSessions.length) * 100) : 0;

  const handlePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!paymentAmount) return;
    onUpdatePayment(student.id, parseFloat(paymentAmount));
    setPaymentAmount('');
  };

  const handleGenerateReport = async () => {
    setIsGenerating(true);
    const report = await generateStudentReport(student, studentSessions.slice(0, 5)); // Send last 5 sessions
    setAiReport(report);
    setIsGenerating(false);
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex justify-end">
      <div className="w-full max-w-lg bg-slate-50 h-full shadow-2xl animate-in slide-in-from-right duration-300 flex flex-col">
        {/* Header */}
        <div className="bg-white p-6 border-b border-slate-200 flex justify-between items-start">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">{student.name}</h2>
            <div className="flex flex-wrap items-center gap-2 mt-2">
               <span className={`text-xs px-2 py-0.5 rounded-full border ${student.status === 'Active' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-slate-100 text-slate-600 border-slate-200'}`}>
                    {student.status}
               </span>
               {student.classTypes.map(type => (
                    <span key={type} className={`text-xs px-2 py-0.5 rounded-full ${type === ClassType.OneOnOne ? 'bg-blue-100 text-blue-700' : 'bg-orange-100 text-orange-700'}`}>
                        {type}
                    </span>
               ))}
              <span className="text-slate-300">•</span>
              <span className="text-sm text-slate-500">Joined {new Date(student.joinedDate).toLocaleDateString()}</span>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        {/* Balance Card */}
        <div className="p-6 pb-2">
            <div className="bg-indigo-600 rounded-xl p-5 text-white shadow-lg shadow-indigo-200">
                <div className="flex justify-between items-center mb-4">
                    <div>
                        <p className="text-indigo-200 text-sm font-medium">Current Balance</p>
                        <h3 className="text-3xl font-bold mt-1">
                            {student.balance > 0 ? `-$${student.balance}` : `$${Math.abs(student.balance)}`}
                        </h3>
                        <p className="text-xs text-indigo-200 mt-1">
                            {student.balance > 0 ? 'Payment Overdue' : 'Credit Available'}
                        </p>
                    </div>
                    <div className="bg-white/20 p-3 rounded-full">
                        <DollarSign className="w-6 h-6 text-white" />
                    </div>
                </div>
                <form onSubmit={handlePayment} className="flex gap-2">
                    <input 
                        type="number" 
                        placeholder="Add Payment" 
                        className="flex-1 bg-indigo-800/50 border border-indigo-500/50 text-white placeholder-indigo-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-white/20"
                        value={paymentAmount}
                        onChange={e => setPaymentAmount(e.target.value)}
                    />
                    <button type="submit" className="bg-white text-indigo-700 px-4 py-2 rounded-lg text-sm font-semibold hover:bg-indigo-50 transition-colors">
                        Pay
                    </button>
                </form>
            </div>
        </div>

        {/* Tabs */}
        <div className="px-6 flex gap-6 border-b border-slate-200">
            <button 
                onClick={() => setActiveTab('overview')}
                className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'overview' ? 'text-indigo-600' : 'text-slate-500'}`}
            >
                Overview
                {activeTab === 'overview' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-600 rounded-t-full"></div>}
            </button>
            <button 
                onClick={() => setActiveTab('history')}
                className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'history' ? 'text-indigo-600' : 'text-slate-500'}`}
            >
                History
                {activeTab === 'history' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-600 rounded-t-full"></div>}
            </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 space-y-6">
            {activeTab === 'overview' ? (
                <>
                    {/* Stats Grid */}
                    <div className="grid grid-cols-2 gap-4">
                        <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                            <p className="text-xs text-slate-500 uppercase font-semibold">Attendance Rate</p>
                            <p className="text-xl font-bold text-slate-800 mt-1">{attendanceRate}%</p>
                        </div>
                        <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                            <p className="text-xs text-slate-500 uppercase font-semibold">Total Classes</p>
                            <p className="text-xl font-bold text-slate-800 mt-1">{attendedCount}</p>
                        </div>
                    </div>

                    {/* Class Packages */}
                    {student.packages && student.packages.length > 0 && (
                        <div className="space-y-3">
                            {student.packages.map((pkg, idx) => {
                                const attendedForType = studentSessions.filter(s => s.type === pkg.type && s.status === AttendanceStatus.Present).length;
                                const progress = Math.min(100, Math.round((attendedForType / pkg.total) * 100));

                                return (
                                    <div key={idx} className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
                                        <div className="flex justify-between items-end mb-2">
                                            <h3 className="font-semibold text-slate-800">{pkg.type} Package</h3>
                                            <p className="text-sm font-medium text-slate-600">{attendedForType} / {pkg.total}</p>
                                        </div>
                                        <div className="w-full bg-slate-100 rounded-full h-2.5">
                                            <div 
                                                className={`h-2.5 rounded-full transition-all duration-500 ${pkg.type === ClassType.OneOnOne ? 'bg-blue-500' : 'bg-orange-500'}`} 
                                                style={{ width: `${progress}%` }}
                                            ></div>
                                        </div>
                                        {progress >= 100 ? (
                                            <p className="text-xs text-red-500 mt-2 font-medium">Package complete! Time to renew.</p>
                                        ) : (
                                            <p className="text-xs text-slate-400 mt-2">{pkg.total - attendedForType} classes remaining</p>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    )}

                    {/* AI Report Section */}
                    <div className="bg-violet-50 rounded-xl p-5 border border-violet-100">
                        <div className="flex justify-between items-center mb-3">
                            <h3 className="font-semibold text-violet-900 flex items-center gap-2">
                                <Sparkles className="w-4 h-4" /> AI Progress Report
                            </h3>
                            <button 
                                onClick={handleGenerateReport}
                                disabled={isGenerating}
                                className="text-xs bg-violet-200 text-violet-800 px-2 py-1 rounded hover:bg-violet-300 disabled:opacity-50 transition-colors"
                            >
                                {isGenerating ? 'Drafting...' : 'Generate New'}
                            </button>
                        </div>
                        {aiReport ? (
                            <div className="bg-white p-4 rounded-lg border border-violet-100 text-sm text-slate-600 leading-relaxed whitespace-pre-line">
                                {aiReport}
                            </div>
                        ) : (
                            <p className="text-sm text-violet-700/70">
                                Click generate to create a professional email update for {student.parentName}.
                            </p>
                        )}
                    </div>

                    {/* Notes */}
                    <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
                        <h3 className="font-semibold text-slate-800 mb-3">Student Notes</h3>
                        <p className="text-sm text-slate-600 whitespace-pre-line">{student.notes || "No notes available."}</p>
                    </div>
                </>
            ) : (
                <div className="space-y-4">
                    <h3 className="font-semibold text-slate-800">Recent Sessions</h3>
                    {studentSessions.length === 0 && <p className="text-sm text-slate-400">No session history found.</p>}
                    {studentSessions.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(session => (
                        <div key={session.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-start gap-4">
                             <div className="p-2 bg-slate-50 rounded-lg text-center min-w-[3.5rem]">
                                <p className="text-xs font-bold text-slate-500 uppercase">{new Date(session.date).toLocaleDateString('en-US', { month: 'short' })}</p>
                                <p className="text-lg font-bold text-slate-800">{new Date(session.date).getDate()}</p>
                            </div>
                            <div>
                                <div className="flex items-center gap-2">
                                    <h4 className="font-medium text-slate-800">{session.topic}</h4>
                                     <span className={`text-[10px] px-2 py-0.5 rounded-full border ${session.type === ClassType.OneOnOne ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-orange-50 text-orange-700 border-orange-100'}`}>
                                        {session.type}
                                    </span>
                                </div>
                                <p className="text-xs text-slate-500 mt-1">{session.notes}</p>
                                <span className={`inline-block mt-2 text-xs px-2 py-0.5 rounded-full ${
                                    session.status === AttendanceStatus.Present ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'
                                }`}>
                                    {session.status}
                                </span>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

