import React, { useState } from 'react';
import { Student, Session, Payment, AttendanceStatus, ClassType, ClassPackage } from '../types';
import { X, Mail, DollarSign, Calendar, Sparkles, PlusCircle } from 'lucide-react';
import { generateStudentReport } from '../services/geminiService';

interface StudentDetailProps {
  student: Student;
  sessions: Session[];
  payments: Payment[];
  onClose: () => void;
  onUpdatePayment: (studentId: string, amount: number) => void;
  onUpdateStudent: (student: Student) => void;
}

const StudentDetail: React.FC<StudentDetailProps> = ({ student, sessions, payments, onClose, onUpdatePayment, onUpdateStudent }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'history'>('overview');
  const [paymentAmount, setPaymentAmount] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  // Renew Package State
  const [isRenewing, setIsRenewing] = useState(false);
  const [renewType, setRenewType] = useState<ClassType>(ClassType.OneOnOne);
  const [renewClasses, setRenewClasses] = useState(10);
  const [renewCost, setRenewCost] = useState(400);

  const studentSessions = sessions.filter(s => s.studentIds.includes(student.id));
  const attendedCount = studentSessions.filter(s => s.status === AttendanceStatus.Present).length;
  const attendanceRate = studentSessions.length ? Math.round((attendedCount / studentSessions.length) * 100) : 0;

  const handlePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!paymentAmount) return;
    onUpdatePayment(student.id, parseFloat(paymentAmount));
    setPaymentAmount('');
  };

  const handleGenerateReport = async () => {
    setIsGenerating(true);
    const report = await generateStudentReport(student, studentSessions.slice(0, 5)); // Send last 5 sessions
    setAiReport(report);
    setIsGenerating(false);
  };

  const handleRenewPackage = (e: React.FormEvent) => {
      e.preventDefault();

      const newPackages = [...(student.packages || [])];
      const existingPackageIndex = newPackages.findIndex(p => p.type === renewType);

      if (existingPackageIndex >= 0) {
          // Add to existing package
          newPackages[existingPackageIndex] = {
              ...newPackages[existingPackageIndex],
              total: newPackages[existingPackageIndex].total + renewClasses,
              active: true
          };
      } else {
          // Create new package
          newPackages.push({
              type: renewType,
              total: renewClasses,
              active: true
          });
      }

      // Add payment/credit logic. If they paid renewCost, their balance goes down (credit increases)
      // Example: Balance is 0. They pay 400. Balance becomes -400 (Credit).
      const newBalance = student.balance - renewCost;

      // Update classTypes if this is a new type for them
      const newClassTypes = student.classTypes.includes(renewType) 
        ? student.classTypes 
        : [...student.classTypes, renewType];

      onUpdateStudent({
          ...student,
          packages: newPackages,
          balance: newBalance,
          classTypes: newClassTypes
      });

      setIsRenewing(false);
      // Reset form defaults
      setRenewClasses(10);
      setRenewCost(400);
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex justify-end">
      <div className="w-full max-w-lg bg-slate-50 h-full shadow-2xl animate-in slide-in-from-right duration-300 flex flex-col">
        {/* Header */}
        <div className="bg-white p-6 border-b border-slate-200 flex justify-between items-start">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">{student.name}</h2>
            <div className="flex flex-wrap items-center gap-2 mt-2">
               <span className={`text-xs px-2 py-0.5 rounded-full border ${student.status === 'Active' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-slate-100 text-slate-600 border-slate-200'}`}>
                    {student.status}
               </span>
               {student.classTypes.map(type => (
                    <span key={type} className={`text-xs px-2 py-0.5 rounded-full ${type === ClassType.OneOnOne ? 'bg-blue-100 text-blue-700' : 'bg-orange-100 text-orange-700'}`}>
                        {type}
                    </span>
               ))}
              <span className="text-slate-300">•</span>
              <span className="text-sm text-slate-500">Joined {new Date(student.joinedDate).toLocaleDateString()}</span>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        {/* Balance Card */}
        <div className="p-6 pb-2">
            <div className="bg-indigo-600 rounded-xl p-5 text-white shadow-lg shadow-indigo-200">
                <div className="flex justify-between items-center mb-4">
                    <div>
                        <p className="text-indigo-200 text-sm font-medium">Current Balance</p>
                        <h3 className="text-3xl font-bold mt-1">
                            {student.balance > 0 ? `-$${student.balance}` : `$${Math.abs(student.balance)}`}
                        </h3>
                        <p className="text-xs text-indigo-200 mt-1">
                            {student.balance > 0 ? 'Payment Overdue' : 'Credit Available'}
                        </p>
                    </div>
                    <div className="bg-white/20 p-3 rounded-full">
                        <DollarSign className="w-6 h-6 text-white" />
                    </div>
                </div>
                <form onSubmit={handlePayment} className="flex gap-2">
                    <input 
                        type="number" 
                        placeholder="Add Payment" 
                        className="flex-1 bg-indigo-800/50 border border-indigo-500/50 text-white placeholder-indigo-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-white/20"
                        value={paymentAmount}
                        onChange={e => setPaymentAmount(e.target.value)}
                    />
                    <button type="submit" className="bg-white text-indigo-700 px-4 py-2 rounded-lg text-sm font-semibold hover:bg-indigo-50 transition-colors">
                        Pay
                    </button>
                </form>
            </div>
        </div>

        {/* Tabs */}
        <div className="px-6 flex gap-6 border-b border-slate-200">
            <button 
                onClick={() => setActiveTab('overview')}
                className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'overview' ? 'text-indigo-600' : 'text-slate-500'}`}
            >
                Overview
                {activeTab === 'overview' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-600 rounded-t-full"></div>}
            </button>
            <button 
                onClick={() => setActiveTab('history')}
                className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'history' ? 'text-indigo-600' : 'text-slate-500'}`}
            >
                History
                {activeTab === 'history' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-600 rounded-t-full"></div>}
            </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 space-y-6">
            {activeTab === 'overview' ? (
                <>
                    {/* Renew / Add Package Section */}
                    <div className="bg-slate-100 rounded-xl p-4 border border-slate-200">
                        {!isRenewing ? (
                            <button 
                                onClick={() => setIsRenewing(true)}
                                className="w-full flex items-center justify-center gap-2 bg-white p-3 rounded-lg border border-slate-200 text-slate-700 font-medium hover:bg-slate-50 transition-colors"
                            >
                                <PlusCircle className="w-5 h-5 text-indigo-600" />
                                Renew Package / Add Credits
                            </button>
                        ) : (
                            <form onSubmit={handleRenewPackage} className="space-y-3 animate-in fade-in slide-in-from-top-2">
                                <div className="flex justify-between items-center mb-2">
                                    <h4 className="font-semibold text-slate-800">Add Sessions</h4>
                                    <button type="button" onClick={() => setIsRenewing(false)} className="text-slate-400 hover:text-slate-600"><X className="w-4 h-4" /></button>
                                </div>
                                <div>
                                    <label className="block text-xs font-medium text-slate-500 mb-1">Program Type</label>
                                    <select 
                                        value={renewType}
                                        onChange={e => setRenewType(e.target.value as ClassType)}
                                        className="w-full p-2 rounded-md border text-sm"
                                    >
                                        <option value={ClassType.OneOnOne}>One-on-One</option>
                                        <option value={ClassType.Group}>One-on-Two (Group)</option>
                                    </select>
                                </div>
                                <div className="grid grid-cols-2 gap-3">
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">No. of Sessions</label>
                                        <input 
                                            type="number" 
                                            min="1"
                                            value={renewClasses} 
                                            onChange={e => setRenewClasses(parseInt(e.target.value) || 0)}
                                            className="w-full p-2 rounded-md border text-sm"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Amount Paid ($)</label>
                                        <input 
                                            type="number" 
                                            min="0"
                                            value={renewCost} 
                                            onChange={e => setRenewCost(parseFloat(e.target.value) || 0)}
                                            className="w-full p-2 rounded-md border text-sm"
                                        />
                                    </div>
                                </div>
                                <button type="submit" className="w-full bg-indigo-600 text-white py-2 rounded-lg text-sm font-medium hover:bg-indigo-700">
                                    Confirm Renewal
                                </button>
                            </form>
                        )}
                    </div>

                    {/* Stats Grid */}
                    <div className="grid grid-cols-2 gap-4">
                        <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                            <p className="text-xs text-slate-500 uppercase font-semibold">Attendance Rate</p>
                            <p className="text-xl font-bold text-slate-800 mt-1">{attendanceRate}%</p>
                        </div>
                        <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                            <p className="text-xs text-slate-500 uppercase font-semibold">Total Classes</p>
                            <p className="text-xl font-bold text-slate-800 mt-1">{attendedCount}</p>
                        </div>
                    </div>

                    {/* Class Packages */}
                    {student.packages && student.packages.length > 0 && (
                        <div className="space-y-3">
                            {student.packages.map((pkg, idx) => {
                                const attendedForType = studentSessions.filter(s => s.type === pkg.type && s.status === AttendanceStatus.Present).length;
                                const progress = Math.min(100, Math.round((attendedForType / pkg.total) * 100));

                                return (
                                    <div key={idx} className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
                                        <div className="flex justify-between items-end mb-2">
                                            <h3 className="font-semibold text-slate-800">{pkg.type} Package</h3>
                                            <p className="text-sm font-medium text-slate-600">{attendedForType} / {pkg.total}</p>
                                        </div>
                                        <div className="w-full bg-slate-100 rounded-full h-2.5">
                                            <div 
                                                className={`h-2.5 rounded-full transition-all duration-500 ${pkg.type === ClassType.OneOnOne ? 'bg-blue-500' : 'bg-orange-500'}`} 
                                                style={{ width: `${progress}%` }}
                                            ></div>
                                        </div>
                                        {progress >= 100 ? (
                                            <p className="text-xs text-red-500 mt-2 font-medium">Package complete! Time to renew.</p>
                                        ) : (
                                            <p className="text-xs text-slate-400 mt-2">{pkg.total - attendedForType} classes remaining</p>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    )}

                    {/* AI Report Section */}
                    <div className="bg-violet-50 rounded-xl p-5 border border-violet-100">
                        <div className="flex justify-between items-center mb-3">
                            <h3 className="font-semibold text-violet-900 flex items-center gap-2">
                                <Sparkles className="w-4 h-4" /> AI Progress Report
                            </h3>
                            <button 
                                onClick={handleGenerateReport}
                                disabled={isGenerating}
                                className="text-xs bg-violet-200 text-violet-800 px-2 py-1 rounded hover:bg-violet-300 disabled:opacity-50 transition-colors"
                            >
                                {isGenerating ? 'Drafting...' : 'Generate New'}
                            </button>
                        </div>
                        {aiReport ? (
                            <div className="bg-white p-4 rounded-lg border border-violet-100 text-sm text-slate-600 leading-relaxed whitespace-pre-line">
                                {aiReport}
                            </div>
                        ) : (
                            <p className="text-sm text-violet-700/70">
                                Click generate to create a professional email update for {student.parentName}.
                            </p>
                        )}
                    </div>

                    {/* Notes */}
                    <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
                        <h3 className="font-semibold text-slate-800 mb-3">Student Notes</h3>
                        <p className="text-sm text-slate-600 whitespace-pre-line">{student.notes || "No notes available."}</p>
                    </div>
                </>
            ) : (
                <div className="space-y-4">
                    <h3 className="font-semibold text-slate-800">Recent Sessions</h3>
                    {studentSessions.length === 0 && <p className="text-sm text-slate-400">No session history found.</p>}
                    {studentSessions.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(session => {
                        // Find this student's specific status
                        const myStatus = session.studentStatuses?.find(s => s.studentId === student.id)?.status || session.status;

                        return (
                            <div key={session.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-start gap-4">
                                <div className="p-2 bg-slate-50 rounded-lg text-center min-w-[3.5rem]">
                                    <p className="text-xs font-bold text-slate-500 uppercase">{new Date(session.date).toLocaleDateString('en-US', { month: 'short' })}</p>
                                    <p className="text-lg font-bold text-slate-800">{new Date(session.date).getDate()}</p>
                                </div>
                                <div>
                                    <div className="flex items-center gap-2">
                                        <h4 className="font-medium text-slate-800">{session.topic}</h4>
                                        <span className={`text-[10px] px-2 py-0.5 rounded-full border ${session.type === ClassType.OneOnOne ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-orange-50 text-orange-700 border-orange-100'}`}>
                                            {session.type}
                                        </span>
                                    </div>
                                    <p className="text-xs text-slate-500 mt-1">{session.notes}</p>
                                    <span className={`inline-block mt-2 text-xs px-2 py-0.5 rounded-full ${
                                        myStatus === AttendanceStatus.Present ? 'bg-emerald-100 text-emerald-700' : 
                                        myStatus === AttendanceStatus.Late ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                                    }`}>
                                        {myStatus}
                                    </span>
                                </div>
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default StudentDetail;

import React, { useState, useEffect } from 'react';
import { Session, Student, AttendanceStatus, ClassType, StudentSessionStatus } from '../types';
import { Calendar, Clock, CheckCircle, XCircle, AlertCircle, Sparkles, ChevronLeft, ChevronRight, X, Edit, Trash2, Search, ChevronDown, ChevronUp } from 'lucide-react';
import { generateLessonPlan } from '../services/geminiService';
import { PRICE_1ON1, PRICE_GROUP } from '../constants';

interface SessionLogProps {
  sessions: Session[];
  students: Student[];
  onAddSession: (session: Omit<Session, 'id'>) => void;
  onUpdateSession: (session: Session) => void;
  onDeleteSession: (id: string) => void;
  onSelectStudent?: (student: Student) => void;
}

const SessionLog: React.FC<SessionLogProps> = ({ sessions, students, onAddSession, onUpdateSession, onDeleteSession, onSelectStudent }) => {
  const [currentMonth, setCurrentMonth] = useState(new Date());

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);

  // Form State
  const [selectedStudents, setSelectedStudents] = useState<string[]>([]);
  const [studentStatuses, setStudentStatuses] = useState<Record<string, AttendanceStatus>>({});

  const [date, setDate] = useState('');
  const [time, setTime] = useState('14:00');
  const [topic, setTopic] = useState('');
  const [sessionType, setSessionType] = useState<ClassType>(ClassType.OneOnOne);
  const [notes, setNotes] = useState('');

  // Dropdown UI State
  const [isStudentDropdownOpen, setIsStudentDropdownOpen] = useState(false);
  const [studentSearch, setStudentSearch] = useState('');

  // AI State
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [generatedPlan, setGeneratedPlan] = useState('');

  // Filter students for dropdown
  const filteredStudents = students.filter(s => 
    s.status === 'Active' && 
    s.name.toLowerCase().includes(studentSearch.toLowerCase())
  );

  // Calendar Logic
  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const days = new Date(year, month + 1, 0).getDate();
    const firstDay = new Date(year, month, 1).getDay();
    return { days, firstDay, year, month };
  };

  const { days, firstDay, year, month } = getDaysInMonth(currentMonth);

  const prevMonth = () => setCurrentMonth(new Date(year, month - 1, 1));
  const nextMonth = () => setCurrentMonth(new Date(year, month + 1, 1));

  const openAddModal = (day?: number) => {
    resetForm();
    if (day) {
        const m = month + 1;
        const dateStr = `${year}-${m < 10 ? '0' + m : m}-${day < 10 ? '0' + day : day}`;
        setDate(dateStr);
    } else {
        setDate(new Date().toISOString().split('T')[0]);
    }
    setEditingSessionId(null);
    setIsModalOpen(true);
  };

  const openEditModal = (session: Session) => {
    setEditingSessionId(session.id);
    setSelectedStudents(session.studentIds);

    // Convert array of statuses to map for easy form handling
    const statusMap: Record<string, AttendanceStatus> = {};
    if (session.studentStatuses) {
        session.studentStatuses.forEach(s => statusMap[s.studentId] = s.status);
    } else {
        // Backwards compatibility or default
        session.studentIds.forEach(id => statusMap[id] = session.status);
    }
    setStudentStatuses(statusMap);

    setDate(new Date(session.date).toISOString().split('T')[0]);
    setTime(new Date(session.date).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }));
    setTopic(session.topic);
    setSessionType(session.type);
    setNotes(session.notes);
    setGeneratedPlan('');
    setIsModalOpen(true);
  };

  const handleStudentToggle = (id: string) => {
    let newSelected = [];
    if (selectedStudents.includes(id)) {
      newSelected = selectedStudents.filter(s => s !== id);
      // Remove status entry
      const newStatuses = { ...studentStatuses };
      delete newStatuses[id];
      setStudentStatuses(newStatuses);
    } else {
      if (selectedStudents.length >= 2) return; // Limit to 2
      newSelected = [...selectedStudents, id];
      // Add default status
      setStudentStatuses({ ...studentStatuses, [id]: AttendanceStatus.Present });
    }
    setSelectedStudents(newSelected);

    // Auto switch type based on count
    if (newSelected.length === 2) setSessionType(ClassType.Group);
    else if (newSelected.length === 1) setSessionType(ClassType.OneOnOne);
  };

  const handleStatusChange = (studentId: string, status: AttendanceStatus) => {
      setStudentStatuses({ ...studentStatuses, [studentId]: status });
  }

  const handleGeneratePlan = async () => {
    if (!topic || selectedStudents.length === 0) return;
    setIsGeneratingPlan(true);
    const studentNames = students.filter(s => selectedStudents.includes(s.id)).map(s => s.name);
    const plan = await generateLessonPlan(topic, studentNames, 60);
    setGeneratedPlan(plan);
    setNotes(prev => prev + (prev ? '\n\n' : '') + "Lesson Plan: " + topic);
    setIsGeneratingPlan(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedStudents.length === 0) return;

    const pricePerStudent = sessionType === ClassType.OneOnOne ? PRICE_1ON1 : PRICE_GROUP;
    const totalPrice = pricePerStudent * selectedStudents.length;

    // Construct studentStatuses array
    const studentStatusesArray: StudentSessionStatus[] = selectedStudents.map(id => ({
        studentId: id,
        status: studentStatuses[id] || AttendanceStatus.Present
    }));

    // Determine overall status (if all present -> present, mixed -> present (for simplicity of tracking active sessions))
    const overallStatus = AttendanceStatus.Present;

    const sessionData = {
      studentIds: selectedStudents,
      date: `${date}T${time}:00`,
      durationMinutes: 60,
      status: overallStatus,
      studentStatuses: studentStatusesArray,
      type: sessionType,
      topic,
      notes: generatedPlan ? `${notes}\n\n--- AI Plan ---\n${generatedPlan}` : notes,
      price: totalPrice
    };

    if (editingSessionId) {
        onUpdateSession({ ...sessionData, id: editingSessionId });
    } else {
        onAddSession(sessionData);
    }

    setIsModalOpen(false);
    resetForm();
  };

  const handleDelete = () => {
    if (editingSessionId && window.confirm("Delete this session?")) {
        onDeleteSession(editingSessionId);
        setIsModalOpen(false);
    }
  }

  const resetForm = () => {
    setSelectedStudents([]);
    setStudentStatuses({});
    setTopic('');
    setNotes('');
    setGeneratedPlan('');
    setSessionType(ClassType.OneOnOne);
    setEditingSessionId(null);
    setStudentSearch('');
    setIsStudentDropdownOpen(false);
  };

  const renderCalendar = () => {
    const blanks = Array(firstDay).fill(null);
    const daySlots = Array.from({ length: days }, (_, i) => i + 1);
    const allSlots = [...blanks, ...daySlots];

    return (
        <div className="grid grid-cols-7 gap-px bg-slate-200 rounded-lg overflow-hidden border border-slate-200">
            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => (
                <div key={d} className="bg-slate-50 p-2 text-center text-xs font-semibold text-slate-500 uppercase">
                    {d}
                </div>
            ))}
            {allSlots.map((day, index) => {
                if (!day) return <div key={`blank-${index}`} className="bg-white h-32 md:h-40" />;

                // Find sessions for this day
                const currentDayStr = `${year}-${(month + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
                const daySessions = sessions.filter(s => s.date.startsWith(currentDayStr));

                return (
                    <div 
                        key={day} 
                        onClick={() => openAddModal(day as number)}
                        className="bg-white h-32 md:h-40 p-2 border-t border-slate-50 hover:bg-slate-50 transition-colors cursor-pointer overflow-y-auto"
                    >
                        <div className="flex justify-between items-start mb-1">
                            <span className={`text-sm font-semibold ${
                                new Date().toDateString() === new Date(year, month, day as number).toDateString() 
                                ? 'bg-indigo-600 text-white w-6 h-6 flex items-center justify-center rounded-full' 
                                : 'text-slate-700'
                            }`}>
                                {day}
                            </span>
                        </div>
                        <div className="space-y-1">
                            {daySessions.map(session => (
                                <div 
                                    key={session.id}
                                    onClick={(e) => { e.stopPropagation(); openEditModal(session); }}
                                    className={`text-[10px] p-1.5 rounded border border-l-2 shadow-sm cursor-pointer hover:opacity-80 transition-opacity ${
                                        session.type === ClassType.OneOnOne 
                                        ? 'bg-blue-50 border-blue-100 border-l-blue-500 text-blue-700' 
                                        : 'bg-orange-50 border-orange-100 border-l-orange-500 text-orange-700'
                                    }`}
                                >
                                    <div className="font-semibold truncate">{session.topic}</div>
                                    <div className="text-xs opacity-75">
                                        {new Date(session.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                    </div>
                                    <div className="truncate opacity-75">
                                        {session.studentIds.map(sid => students.find(s => s.id === sid)?.name.split(' ')[0]).join(', ')}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                );
            })}
        </div>
    );
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-4">
            <h2 className="text-xl font-bold text-slate-800">
                {currentMonth.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
            </h2>
            <div className="flex items-center bg-white rounded-lg border border-slate-200 shadow-sm">
                <button onClick={prevMonth} className="p-1.5 hover:bg-slate-50 text-slate-600"><ChevronLeft className="w-5 h-5" /></button>
                <div className="w-px h-6 bg-slate-200"></div>
                <button onClick={nextMonth} className="p-1.5 hover:bg-slate-50 text-slate-600"><ChevronRight className="w-5 h-5" /></button>
            </div>
        </div>
        <button
          onClick={() => openAddModal()}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
        >
          <Calendar className="w-4 h-4" />
          Log Session
        </button>
      </div>

      {renderCalendar()}

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto animate-in zoom-in-95 duration-200">
                <div className="flex justify-between items-center p-6 border-b border-slate-100">
                    <h3 className="text-lg font-bold text-slate-800">
                        {editingSessionId ? 'Edit Session' : 'Log New Session'}
                    </h3>
                    <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                        <X className="w-5 h-5" />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="p-6 space-y-4">
                    <div className="grid grid-cols-1 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">Session Type</label>
                            <select
                                value={sessionType}
                                onChange={e => setSessionType(e.target.value as ClassType)}
                                className="w-full p-2 border rounded-md"
                            >
                                <option value={ClassType.OneOnOne}>One-on-One</option>
                                <option value={ClassType.Group}>One-on-Two (Group)</option>
                            </select>
                        </div>

                        {/* Student Dropdown Selector */}
                        <div className="relative">
                            <label className="block text-sm font-medium text-slate-700 mb-2">Select Students</label>

                            {/* Selected Students Chips */}
                            <div className="flex flex-wrap gap-2 mb-2">
                                {selectedStudents.map(id => {
                                    const s = students.find(student => student.id === id);
                                    if(!s) return null;
                                    return (
                                        <div key={id} className="bg-indigo-50 border border-indigo-200 text-indigo-700 px-3 py-1 rounded-full text-sm flex items-center gap-2">
                                            {s.name}
                                            <button type="button" onClick={() => handleStudentToggle(id)}><X className="w-3 h-3" /></button>
                                        </div>
                                    )
                                })}
                            </div>

                            <button 
                                type="button"
                                onClick={() => setIsStudentDropdownOpen(!isStudentDropdownOpen)}
                                className="w-full p-2 border rounded-md flex justify-between items-center bg-white hover:bg-slate-50 text-left"
                            >
                                <span className="text-slate-500 text-sm">
                                    {selectedStudents.length === 0 ? "Search and select students..." : `${selectedStudents.length} selected`}
                                </span>
                                {isStudentDropdownOpen ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
                            </button>

                            {isStudentDropdownOpen && (
                                <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-lg z-20 max-h-60 overflow-hidden flex flex-col">
                                    <div className="p-2 border-b border-slate-100">
                                        <div className="relative">
                                            <Search className="absolute left-2 top-1/2 transform -translate-y-1/2 w-4 h-4 text-slate-400" />
                                            <input 
                                                autoFocus
                                                type="text" 
                                                placeholder="Search name..."
                                                className="w-full pl-8 pr-2 py-1.5 text-sm bg-slate-50 rounded-md focus:outline-none"
                                                value={studentSearch}
                                                onChange={e => setStudentSearch(e.target.value)}
                                            />
                                        </div>
                                    </div>
                                    <div className="overflow-y-auto flex-1 p-1">
                                        {filteredStudents.length === 0 && <div className="p-2 text-center text-xs text-slate-400">No active students found.</div>}
                                        {filteredStudents.map(s => (
                                            <button
                                                key={s.id}
                                                type="button"
                                                onClick={() => handleStudentToggle(s.id)}
                                                disabled={!selectedStudents.includes(s.id) && selectedStudents.length >= 2}
                                                className={`w-full text-left px-3 py-2 text-sm rounded-md flex items-center justify-between ${
                                                    selectedStudents.includes(s.id) ? 'bg-indigo-50 text-indigo-700' : 'hover:bg-slate-50 text-slate-700 disabled:opacity-50'
                                                }`}
                                            >
                                                <span>{s.name}</span>
                                                {selectedStudents.includes(s.id) && <CheckCircle className="w-4 h-4" />}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Attendance Status Per Student */}
                    {selectedStudents.length > 0 && (
                        <div className="bg-slate-50 p-3 rounded-lg border border-slate-100 space-y-2">
                            <label className="block text-xs font-semibold text-slate-500 uppercase">Attendance Status</label>
                            {selectedStudents.map(id => {
                                const s = students.find(student => student.id === id);
                                if (!s) return null;
                                return (
                                    <div key={id} className="flex justify-between items-center gap-4">
                                        <span className="text-sm font-medium text-slate-700 truncate">{s.name}</span>
                                        <select 
                                            value={studentStatuses[id] || AttendanceStatus.Present}
                                            onChange={(e) => handleStatusChange(id, e.target.value as AttendanceStatus)}
                                            className={`text-sm p-1.5 rounded border ${
                                                studentStatuses[id] === AttendanceStatus.Present ? 'bg-emerald-50 border-emerald-200 text-emerald-700' :
                                                studentStatuses[id] === AttendanceStatus.Late ? 'bg-amber-50 border-amber-200 text-amber-700' :
                                                'bg-red-50 border-red-200 text-red-700'
                                            }`}
                                        >
                                            {Object.values(AttendanceStatus).map(status => (
                                                <option key={status} value={status}>{status}</option>
                                            ))}
                                        </select>
                                    </div>
                                );
                            })}
                        </div>
                    )}

                    <div className="grid grid-cols-2 gap-4">
                        <input
                            type="date"
                            value={date}
                            onChange={e => setDate(e.target.value)}
                            className="p-2 border rounded-md"
                            required
                        />
                        <input
                            type="time"
                            value={time}
                            onChange={e => setTime(e.target.value)}
                            className="p-2 border rounded-md"
                            required
                        />
                    </div>

                    <div className="flex gap-4">
                        <input
                            placeholder="Topic"
                            value={topic}
                            onChange={e => setTopic(e.target.value)}
                            className="flex-1 p-2 border rounded-md"
                            required
                        />
                    </div>

                    <div className="relative">
                        <textarea
                            placeholder="Session notes..."
                            value={notes}
                            onChange={e => setNotes(e.target.value)}
                            className="w-full p-2 border rounded-md"
                            rows={3}
                        />
                        <button
                            type="button"
                            disabled={!topic || selectedStudents.length === 0 || isGeneratingPlan}
                            onClick={handleGeneratePlan}
                            className="absolute bottom-2 right-2 text-xs flex items-center gap-1 bg-violet-100 text-violet-700 px-2 py-1 rounded-md hover:bg-violet-200 disabled:opacity-50"
                        >
                            <Sparkles className="w-3 h-3" />
                            {isGeneratingPlan ? 'Generating...' : 'AI Plan'}
                        </button>
                    </div>

                    {generatedPlan && (
                        <div className="bg-violet-50 p-3 rounded-md text-xs text-slate-700 max-h-40 overflow-y-auto whitespace-pre-wrap border border-violet-100">
                            <h4 className="font-semibold text-violet-800 mb-1">Generated Plan Preview:</h4>
                            {generatedPlan}
                        </div>
                    )}

                    <div className="flex justify-between pt-2">
                        {editingSessionId ? (
                            <button
                                type="button"
                                onClick={handleDelete}
                                className="flex items-center gap-2 text-red-600 hover:bg-red-50 px-3 py-2 rounded-md transition-colors"
                            >
                                <Trash2 className="w-4 h-4" />
                                Delete
                            </button>
                        ) : <div></div>}

                        <div className="flex gap-2">
                            <button 
                                type="button" 
                                onClick={() => setIsModalOpen(false)}
                                className="px-4 py-2 text-slate-600 hover:bg-slate-50 rounded-md"
                            >
                                Cancel
                            </button>
                            <button 
                                type="submit"
                                className="px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-700"
                            >
                                {editingSessionId ? 'Update Session' : 'Save Session'}
                            </button>
                        </div>
                    </div>
                </form>
            </div>
        </div>
      )}
    </div>
  );
};

export default SessionLog;

import React, { useState } from 'react';
import { Student, Session, Payment, AttendanceStatus, ClassType, ClassPackage } from '../types';
import { X, Sparkles, PlusCircle, Edit2, Save, XCircle } from 'lucide-react';
import { generateStudentReport } from '../services/geminiService';

interface StudentDetailProps {
  student: Student;
  sessions: Session[];
  payments: Payment[]; // Keeping for interface compatibility
  onClose: () => void;
  onUpdatePayment: (studentId: string, amount: number) => void; // Keeping for interface compatibility
  onUpdateStudent: (student: Student) => void;
}

const StudentDetail: React.FC<StudentDetailProps> = ({ student, sessions, onClose, onUpdateStudent }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'history'>('overview');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  // Renew Package State
  const [isRenewing, setIsRenewing] = useState(false);
  const [renewType, setRenewType] = useState<ClassType>(ClassType.OneOnOne);
  const [renewClasses, setRenewClasses] = useState(10);
  const [renewCost, setRenewCost] = useState(400);

  // Edit Package State
  const [editingPackageIndex, setEditingPackageIndex] = useState<number | null>(null);
  const [editRemainingCount, setEditRemainingCount] = useState<number>(0);

  const studentSessions = sessions.filter(s => s.studentIds.includes(student.id));
  const attendedCount = studentSessions.filter(s => s.status === AttendanceStatus.Present).length;
  const attendanceRate = studentSessions.length ? Math.round((attendedCount / studentSessions.length) * 100) : 0;

  const handleGenerateReport = async () => {
    setIsGenerating(true);
    const report = await generateStudentReport(student, studentSessions.slice(0, 5)); // Send last 5 sessions
    setAiReport(report);
    setIsGenerating(false);
  };

  const handleRenewPackage = (e: React.FormEvent) => {
      e.preventDefault();

      const newPackages = [...(student.packages || [])];
      const existingPackageIndex = newPackages.findIndex(p => p.type === renewType);

      if (existingPackageIndex >= 0) {
          // Add to existing package
          newPackages[existingPackageIndex] = {
              ...newPackages[existingPackageIndex],
              total: newPackages[existingPackageIndex].total + renewClasses,
              active: true
          };
      } else {
          // Create new package
          newPackages.push({
              type: renewType,
              total: renewClasses,
              active: true
          });
      }

      const newBalance = student.balance - renewCost;

      const newClassTypes = student.classTypes.includes(renewType) 
        ? student.classTypes 
        : [...student.classTypes, renewType];

      onUpdateStudent({
          ...student,
          packages: newPackages,
          balance: newBalance,
          classTypes: newClassTypes
      });

      setIsRenewing(false);
      setRenewClasses(10);
      setRenewCost(400);
  };

  const startEditing = (index: number, total: number, attended: number) => {
      setEditingPackageIndex(index);
      setEditRemainingCount(total - attended);
  };

  const savePackageEdit = (index: number, attended: number) => {
      if (!student.packages) return;

      const newPackages = [...student.packages];
      // Total = Attended (already happened) + Remaining (future)
      const newTotal = attended + editRemainingCount;

      newPackages[index] = {
          ...newPackages[index],
          total: newTotal
      };

      onUpdateStudent({
          ...student,
          packages: newPackages
      });
      setEditingPackageIndex(null);
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex justify-end">
      <div className="w-full max-w-lg bg-slate-50 h-full shadow-2xl animate-in slide-in-from-right duration-300 flex flex-col">
        {/* Header */}
        <div className="bg-white p-6 border-b border-slate-200 flex justify-between items-start">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">{student.name}</h2>
            <div className="flex flex-wrap items-center gap-2 mt-2">
               <span className={`text-xs px-2 py-0.5 rounded-full border ${student.status === 'Active' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-slate-100 text-slate-600 border-slate-200'}`}>
                    {student.status}
               </span>
               {student.classTypes.map(type => (
                    <span key={type} className={`text-xs px-2 py-0.5 rounded-full ${type === ClassType.OneOnOne ? 'bg-blue-100 text-blue-700' : 'bg-orange-100 text-orange-700'}`}>
                        {type}
                    </span>
               ))}
              <span className="text-slate-300">•</span>
              <span className="text-sm text-slate-500">Joined {new Date(student.joinedDate).toLocaleDateString()}</span>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        {/* Tabs */}
        <div className="px-6 pt-4 flex gap-6 border-b border-slate-200 bg-white">
            <button 
                onClick={() => setActiveTab('overview')}
                className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'overview' ? 'text-indigo-600' : 'text-slate-500'}`}
            >
                Overview
                {activeTab === 'overview' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-600 rounded-t-full"></div>}
            </button>
            <button 
                onClick={() => setActiveTab('history')}
                className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'history' ? 'text-indigo-600' : 'text-slate-500'}`}
            >
                History
                {activeTab === 'history' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-600 rounded-t-full"></div>}
            </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 space-y-6">
            {activeTab === 'overview' ? (
                <>
                    {/* Renew / Add Package Section */}
                    <div className="bg-slate-100 rounded-xl p-4 border border-slate-200">
                        {!isRenewing ? (
                            <button 
                                onClick={() => setIsRenewing(true)}
                                className="w-full flex items-center justify-center gap-2 bg-white p-3 rounded-lg border border-slate-200 text-slate-700 font-medium hover:bg-slate-50 transition-colors"
                            >
                                <PlusCircle className="w-5 h-5 text-indigo-600" />
                                Renew Package / Add Credits
                            </button>
                        ) : (
                            <form onSubmit={handleRenewPackage} className="space-y-3 animate-in fade-in slide-in-from-top-2">
                                <div className="flex justify-between items-center mb-2">
                                    <h4 className="font-semibold text-slate-800">Add Sessions</h4>
                                    <button type="button" onClick={() => setIsRenewing(false)} className="text-slate-400 hover:text-slate-600"><X className="w-4 h-4" /></button>
                                </div>
                                <div>
                                    <label className="block text-xs font-medium text-slate-500 mb-1">Program Type</label>
                                    <select 
                                        value={renewType}
                                        onChange={e => setRenewType(e.target.value as ClassType)}
                                        className="w-full p-2 rounded-md border text-sm"
                                    >
                                        <option value={ClassType.OneOnOne}>One-on-One</option>
                                        <option value={ClassType.Group}>One-on-Two (Group)</option>
                                    </select>
                                </div>
                                <div className="grid grid-cols-2 gap-3">
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">No. of Sessions</label>
                                        <input 
                                            type="number" 
                                            min="1"
                                            value={renewClasses} 
                                            onChange={e => setRenewClasses(parseInt(e.target.value) || 0)}
                                            className="w-full p-2 rounded-md border text-sm"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Amount Paid ($)</label>
                                        <input 
                                            type="number" 
                                            min="0"
                                            value={renewCost} 
                                            onChange={e => setRenewCost(parseFloat(e.target.value) || 0)}
                                            className="w-full p-2 rounded-md border text-sm"
                                        />
                                    </div>
                                </div>
                                <button type="submit" className="w-full bg-indigo-600 text-white py-2 rounded-lg text-sm font-medium hover:bg-indigo-700">
                                    Confirm Renewal
                                </button>
                            </form>
                        )}
                    </div>

                    {/* Stats Grid */}
                    <div className="grid grid-cols-2 gap-4">
                        <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                            <p className="text-xs text-slate-500 uppercase font-semibold">Attendance Rate</p>
                            <p className="text-xl font-bold text-slate-800 mt-1">{attendanceRate}%</p>
                        </div>
                        <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                            <p className="text-xs text-slate-500 uppercase font-semibold">Total Classes</p>
                            <p className="text-xl font-bold text-slate-800 mt-1">{attendedCount}</p>
                        </div>
                    </div>

                    {/* Class Packages */}
                    {student.packages && student.packages.length > 0 && (
                        <div className="space-y-3">
                            {student.packages.map((pkg, idx) => {
                                const attendedForType = studentSessions.filter(s => s.type === pkg.type && s.status === AttendanceStatus.Present).length;
                                const isEditing = editingPackageIndex === idx;
                                const progress = Math.min(100, Math.round((attendedForType / pkg.total) * 100));

                                return (
                                    <div key={idx} className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm transition-all">
                                        <div className="flex justify-between items-center mb-3">
                                            <h3 className="font-semibold text-slate-800">{pkg.type} Package</h3>
                                            {!isEditing && (
                                                <button 
                                                    onClick={() => startEditing(idx, pkg.total, attendedForType)}
                                                    className="p-1 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded"
                                                    title="Edit Remaining Classes"
                                                >
                                                    <Edit2 className="w-4 h-4" />
                                                </button>
                                            )}
                                        </div>

                                        {isEditing ? (
                                            <div className="space-y-3 bg-slate-50 p-3 rounded-lg border border-slate-100">
                                                <div className="flex justify-between text-sm text-slate-600">
                                                    <span>Attended:</span>
                                                    <span className="font-medium">{attendedForType}</span>
                                                </div>
                                                <div>
                                                    <label className="block text-xs font-medium text-slate-500 mb-1">Remaining Classes</label>
                                                    <input 
                                                        type="number"
                                                        min="0"
                                                        value={editRemainingCount}
                                                        onChange={(e) => setEditRemainingCount(parseInt(e.target.value) || 0)}
                                                        className="w-full p-2 border rounded-md text-sm"
                                                        autoFocus
                                                    />
                                                    <p className="text-[10px] text-slate-400 mt-1 text-right">New Total: {attendedForType + editRemainingCount}</p>
                                                </div>
                                                <div className="flex gap-2 justify-end">
                                                    <button 
                                                        onClick={() => setEditingPackageIndex(null)}
                                                        className="p-1.5 text-slate-500 hover:bg-slate-200 rounded"
                                                        title="Cancel"
                                                    >
                                                        <XCircle className="w-5 h-5" />
                                                    </button>
                                                    <button 
                                                        onClick={() => savePackageEdit(idx, attendedForType)}
                                                        className="p-1.5 text-emerald-600 hover:bg-emerald-50 rounded"
                                                        title="Save"
                                                    >
                                                        <Save className="w-5 h-5" />
                                                    </button>
                                                </div>
                                            </div>
                                        ) : (
                                            <>
                                                <div className="flex justify-between items-end mb-2">
                                                     <p className="text-sm font-medium text-slate-600">{attendedForType} / {pkg.total}</p>
                                                </div>
                                                <div className="w-full bg-slate-100 rounded-full h-2.5">
                                                    <div 
                                                        className={`h-2.5 rounded-full transition-all duration-500 ${pkg.type === ClassType.OneOnOne ? 'bg-blue-500' : 'bg-orange-500'}`} 
                                                        style={{ width: `${progress}%` }}
                                                    ></div>
                                                </div>
                                                {progress >= 100 ? (
                                                    <p className="text-xs text-red-500 mt-2 font-medium">Package complete! Time to renew.</p>
                                                ) : (
                                                    <p className="text-xs text-slate-400 mt-2">{pkg.total - attendedForType} classes remaining</p>
                                                )}
                                            </>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    )}

                    {/* AI Report Section */}
                    <div className="bg-violet-50 rounded-xl p-5 border border-violet-100">
                        <div className="flex justify-between items-center mb-3">
                            <h3 className="font-semibold text-violet-900 flex items-center gap-2">
                                <Sparkles className="w-4 h-4" /> AI Progress Report
                            </h3>
                            <button 
                                onClick={handleGenerateReport}
                                disabled={isGenerating}
                                className="text-xs bg-violet-200 text-violet-800 px-2 py-1 rounded hover:bg-violet-300 disabled:opacity-50 transition-colors"
                            >
                                {isGenerating ? 'Drafting...' : 'Generate New'}
                            </button>
                        </div>
                        {aiReport ? (
                            <div className="bg-white p-4 rounded-lg border border-violet-100 text-sm text-slate-600 leading-relaxed whitespace-pre-line">
                                {aiReport}
                            </div>
                        ) : (
                            <p className="text-sm text-violet-700/70">
                                Click generate to create a professional email update for {student.parentName}.
                            </p>
                        )}
                    </div>

                    {/* Notes */}
                    <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
                        <h3 className="font-semibold text-slate-800 mb-3">Student Notes</h3>
                        <p className="text-sm text-slate-600 whitespace-pre-line">{student.notes || "No notes available."}</p>
                    </div>
                </>
            ) : (
                <div className="space-y-4">
                    <h3 className="font-semibold text-slate-800">Recent Sessions</h3>
                    {studentSessions.length === 0 && <p className="text-sm text-slate-400">No session history found.</p>}
                    {studentSessions.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(session => {
                        const myStatus = session.studentStatuses?.find(s => s.studentId === student.id)?.status || session.status;
                        return (
                            <div key={session.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-start gap-4">
                                <div className="p-2 bg-slate-50 rounded-lg text-center min-w-[3.5rem]">
                                    <p className="text-xs font-bold text-slate-500 uppercase">{new Date(session.date).toLocaleDateString('en-US', { month: 'short' })}</p>
                                    <p className="text-lg font-bold text-slate-800">{new Date(session.date).getDate()}</p>
                                </div>
                                <div>
                                    <div className="flex items-center gap-2">
                                        <h4 className="font-medium text-slate-800">{session.topic}</h4>
                                        <span className={`text-[10px] px-2 py-0.5 rounded-full border ${session.type === ClassType.OneOnOne ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-orange-50 text-orange-700 border-orange-100'}`}>
                                            {session.type}
                                        </span>
                                    </div>
                                    <p className="text-xs text-slate-500 mt-1">{session.notes}</p>
                                    <span className={`inline-block mt-2 text-xs px-2 py-0.5 rounded-full ${
                                        myStatus === AttendanceStatus.Present ? 'bg-emerald-100 text-emerald-700' : 
                                        myStatus === AttendanceStatus.Late ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                                    }`}>
                                        {myStatus}
                                    </span>
                                </div>
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default StudentDetail;

import React from 'react';

export enum ClassType {
  OneOnOne = 'One-on-One',
  Group = 'One-on-Two'
}

export enum AttendanceStatus {
  Present = 'Present',
  Absent = 'Absent',
  Late = 'Late',
  Cancelled = 'Cancelled'
}

export type StudentStatus = 'Active' | 'Archived';

export interface ClassPackage {
  type: ClassType;
  total: number; // Total classes purchased
  active: boolean;
}

export interface SkillProgress {
  id: string;
  date: string; // ISO Date
  reading: number; // 0-100
  writing: number;
  listening: number;
  speaking: number;
  notes: string;
}

export interface Student {
  id: string;
  name: string;
  classTypes: ClassType[]; 
  email?: string;
  parentName?: string;
  notes: string;
  balance: number; 
  joinedDate: string;
  status: StudentStatus; 
  packages: ClassPackage[]; 
  progressHistory: SkillProgress[]; // Added progress tracking
}

export interface StudentSessionStatus {
  studentId: string;
  status: AttendanceStatus;
}

export interface Session {
  id: string;
  studentIds: string[];
  date: string; // ISO date string
  durationMinutes: number;
  status: AttendanceStatus; // General status for the session (summary)
  studentStatuses: StudentSessionStatus[]; // Individual status per student
  type: ClassType; 
  topic: string;
  notes: string;
