import { Users, DollarSign, CalendarCheck, TrendingUp, Settings, Trash2, Save } from 'lucide-react';
import { Student, Session, Payment, AttendanceStatus } from '../types';

interface DashboardProps {
  students: Student[];
  sessions: Session[];
  payments: Payment[];
  financialOffset: number;
  onUpdateOffset: (amount: number) => void;
  onClearData: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ students, sessions, payments, financialOffset, onUpdateOffset, onClearData }) => {
  const [showSettings, setShowSettings] = useState(false);
  const [tempOffset, setTempOffset] = useState(financialOffset.toString());

  const handleSaveOffset = () => {
      const val = parseFloat(tempOffset);
      if (!isNaN(val)) {
          onUpdateOffset(val);
      }
      setShowSettings(false);
  };

  // Calculate total revenue
  const totalRevenue = payments.reduce((sum, p) => sum + p.amount, 0) + financialOffset;

  // Calculate attendance rate
  const totalSessions = sessions.length;
  const attendedSessions = sessions.filter(s => s.status === AttendanceStatus.Present).length;
  const attendanceRate = totalSessions > 0 ? Math.round((attendedSessions / totalSessions) * 100) : 0;

  // Active students
  const activeStudents = students.filter(s => s.status === 'Active').length;

  // Outstanding Balance (Total owed by all students)
  const totalOutstanding = students.reduce((sum, s) => sum + (s.balance > 0 ? s.balance : 0), 0);

  // Prepare chart data (Sessions per day for the last 7 days logic simplified for demo)
  // Group sessions by date
  const sessionData = sessions.reduce((acc, session) => {
    const date = new Date(session.date).toLocaleDateString('en-US', { weekday: 'short' });
    const existing = acc.find(item => item.name === date);
    if (existing) {
      existing.count += 1;
    } else {
      acc.push({ name: date, count: 1 });
    }
    return acc;
  }, [] as { name: string; count: number }[]);


  const StatCard = ({ title, value, sub, icon: Icon, color }: any) => (
