                  <div>
                      <label className="block text-sm font-medium text-slate-600 mb-2">Historical Revenue Offset</label>
                      <p className="text-xs text-slate-400 mb-3">Add a starting balance to your Total Revenue (e.g. from before using this app).</p>
                      <div className="flex gap-2">
                          <div className="relative flex-1">
                              <DollarSign className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-slate-400" />
                              <input 
                                  type="number" 
