                          </button>
                      </div>
                  </div>

                  <div className="pt-4 md:pt-0 md:border-l md:border-slate-100 md:pl-8">
                      <label className="block text-sm font-medium text-red-600 mb-2">Danger Zone</label>
                      <p className="text-xs text-slate-400 mb-3">Clear all current students, sessions, and payments to start fresh.</p>
                      <button 
