        />
        <StatCard 
          title="Attendance Rate" 
          value={`${attendanceRate}%`} 
          sub="Last 30 days"
          icon={CalendarCheck} 
          color="bg-violet-500" 
        />
        <StatCard 
          title="Outstanding" 
          value={`$${totalOutstanding}`} 
          sub="Pending payments"
          icon={TrendingUp} 
          color="bg-rose-500" 
        />
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 h-96">
        <h3 className="text-lg font-semibold text-slate-800 mb-6">Weekly Sessions Overview</h3>
