import React, { useState } from 'react';
import { LayoutDashboard, Users, Calendar, Menu, X, BookOpen } from 'lucide-react';
import Dashboard from './components/Dashboard';
import StudentList from './components/StudentList';
import SessionLog from './components/SessionLog';
import StudentDetail from './components/StudentDetail';
import { TabItem, Student, Session, Payment, AttendanceStatus } from './types';
import { INITIAL_STUDENTS, INITIAL_SESSIONS, INITIAL_PAYMENTS } from './constants';

const App: React.FC = () => {
  // Navigation State
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [selectedStudent, setSelectedStudent] = useState<Student | null>(null);

  // Data State
  const [students, setStudents] = useState<Student[]>(INITIAL_STUDENTS);
  const [sessions, setSessions] = useState<Session[]>(INITIAL_SESSIONS);
  const [payments, setPayments] = useState<Payment[]>(INITIAL_PAYMENTS);
  const [financialOffset, setFinancialOffset] = useState(0);

  // Tabs Configuration
  const tabs: TabItem[] = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'students', label: 'Students', icon: Users },
    { id: 'sessions', label: 'Calendar', icon: Calendar },
  ];

  // Actions
  const handleAddStudent = (newStudentData: Omit<Student, 'id' | 'joinedDate' | 'status'>) => {
    const newStudent: Student = {
      ...newStudentData,
      id: `s${Date.now()}`,
      joinedDate: new Date().toISOString(),
      status: 'Active'
    };
    setStudents(prev => [...prev, newStudent]);
  };

  const handleUpdateStudent = (updatedStudent: Student) => {
    setStudents(prev => prev.map(s => s.id === updatedStudent.id ? updatedStudent : s));
    if (selectedStudent?.id === updatedStudent.id) {
        setSelectedStudent(updatedStudent);
    }
  };

  const handleDeleteStudent = (id: string) => {
    setStudents(prev => prev.filter(s => s.id !== id));
    if (selectedStudent?.id === id) setSelectedStudent(null);
  };

  const handleAddSession = (newSessionData: Omit<Session, 'id'>) => {
    const newSession: Session = {
      ...newSessionData,
      id: `sess${Date.now()}`
    };
    setSessions(prev => [...prev, newSession]);
    updateBalancesForSession(newSession, 'add');
  };

  const handleUpdateSession = (updatedSession: Session) => {
    const oldSession = sessions.find(s => s.id === updatedSession.id);
    if (oldSession) {
        updateBalancesForSession(oldSession, 'remove');
    }

    setSessions(prev => prev.map(s => s.id === updatedSession.id ? updatedSession : s));
    updateBalancesForSession(updatedSession, 'add');
  };

  const handleDeleteSession = (sessionId: string) => {
      const session = sessions.find(s => s.id === sessionId);
      if (session) {
          updateBalancesForSession(session, 'remove');
          setSessions(prev => prev.filter(s => s.id !== sessionId));
      }
  };

  const updateBalancesForSession = (session: Session, action: 'add' | 'remove') => {
    const multiplier = action === 'add' ? 1 : -1;
    setStudents(prevStudents => {
        return prevStudents.map(student => {
            // Check if this student is in the session
            if (session.studentIds.includes(student.id)) {
              // Find the specific status for this student
              const statusObj = session.studentStatuses?.find(s => s.studentId === student.id);
              const status = statusObj ? statusObj.status : session.status; // Fallback to main status if missing

              const cost = session.price / session.studentIds.length;

              // Logic: Charge if Present or Late. 
              // Modify this if you want to charge for Absent/Cancelled as well.
              if (status === AttendanceStatus.Present || status === AttendanceStatus.Late) {
                  return { ...student, balance: student.balance + (cost * multiplier) };
              }
            }
            return student;
        });
    });
  };

  const handlePayment = (studentId: string, amount: number) => {
    const newPayment: Payment = {
        id: `p${Date.now()}`,
        studentId,
        amount,
        date: new Date().toISOString(),
        method: 'Manual'
    };
    setPayments(prev => [...prev, newPayment]);

    // Update student balance (decrease balance)
    setStudents(prev => {
        const updated = prev.map(s => 
            s.id === studentId ? { ...s, balance: s.balance - amount } : s
        );
        if (selectedStudent?.id === studentId) {
            const s = updated.find(s => s.id === studentId);
            if (s) setSelectedStudent(s);
        }
        return updated;
    });
  };

  return (
    <div className="flex min-h-screen bg-slate-50 text-slate-900 font-sans">
      {/* Sidebar for Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-white border-r border-slate-200 fixed h-full z-10">
        <div className="p-6 border-b border-slate-100 flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg">
                <BookOpen className="w-5 h-5 text-white" />
            </div>
          <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-violet-600">
            TutorTrack
          </span>
        </div>
        <nav className="flex-1 p-4 space-y-1">
          {tabs.map((tab) => {
            const Icon = tab.icon;
            return (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium rounded-xl transition-all ${
                  activeTab === tab.id
                    ? 'bg-indigo-50 text-indigo-700 shadow-sm ring-1 ring-indigo-200'
                    : 'text-slate-500 hover:bg-slate-50 hover:text-slate-900'
                }`}
              >
                <Icon className={`w-5 h-5 ${activeTab === tab.id ? 'text-indigo-600' : 'text-slate-400'}`} />
                {tab.label}
              </button>
            );
          })}
        </nav>
        <div className="p-4 border-t border-slate-100">
          <div className="bg-indigo-600 rounded-xl p-4 text-white">
            <p className="text-xs font-medium text-indigo-200 mb-1">Pro Tip</p>
            <p className="text-sm leading-snug">Use the AI Assistant in Calendar to plan your next class instantly!</p>
          </div>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 left-0 right-0 bg-white border-b border-slate-200 z-20 px-4 py-3 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-md">
                <BookOpen className="w-4 h-4 text-white" />
            </div>
          <span className="font-bold text-lg text-slate-800">TutorTrack</span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
          {isMobileMenuOpen ? <X className="w-6 h-6 text-slate-600" /> : <Menu className="w-6 h-6 text-slate-600" />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="md:hidden fixed inset-0 bg-white z-10 pt-16 px-4">
          <nav className="space-y-2 mt-4">
            {tabs.map((tab) => {
              const Icon = tab.icon;
              return (
                <button
                  key={tab.id}
                  onClick={() => { setActiveTab(tab.id); setIsMobileMenuOpen(false); }}
                  className={`w-full flex items-center gap-3 px-4 py-4 text-base font-medium rounded-xl transition-colors ${
                    activeTab === tab.id
                      ? 'bg-indigo-50 text-indigo-700'
                      : 'text-slate-500'
                  }`}
                >
                  <Icon className="w-5 h-5" />
                  {tab.label}
                </button>
              );
            })}
          </nav>
        </div>
      )}

      {/* Main Content Area */}
      <main className="flex-1 md:ml-64 pt-20 md:pt-8 px-4 md:px-8 pb-8 max-w-7xl mx-auto w-full">
        <header className="mb-8">
          <h1 className="text-2xl font-bold text-slate-800">
            {tabs.find(t => t.id === activeTab)?.label}
          </h1>
          <p className="text-slate-500 text-sm mt-1">Manage your students and sessions effectively.</p>
        </header>

        {activeTab === 'dashboard' && (
          <Dashboard 
            students={students} 
            sessions={sessions} 
            payments={payments}
            financialOffset={financialOffset}
            onUpdateOffset={setFinancialOffset}
          />
        )}

        {activeTab === 'students' && (
          <StudentList 
            students={students} 
            onAddStudent={handleAddStudent} 
            onUpdateStudent={handleUpdateStudent}
            onDeleteStudent={handleDeleteStudent}
            onSelectStudent={setSelectedStudent}
          />
        )}

        {activeTab === 'sessions' && (
          <SessionLog 
            sessions={sessions} 
            students={students}
            onAddSession={handleAddSession}
            onUpdateSession={handleUpdateSession}
            onDeleteSession={handleDeleteSession}
            onUpdateStudent={handleUpdateStudent}
            onSelectStudent={(s) => {
                setSelectedStudent(s);
            }}
          />
        )}
      </main>

      {/* Student Detail Modal */}
      {selectedStudent && (
        <StudentDetail 
            student={selectedStudent} 
            sessions={sessions}
            payments={payments}
            onClose={() => setSelectedStudent(null)} 
            onUpdatePayment={handlePayment}
            onUpdateStudent={handleUpdateStudent}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Session, Student, AttendanceStatus, ClassType, StudentSessionStatus, SkillProgress } from '../types';
import { Calendar, Clock, CheckCircle, XCircle, AlertCircle, Sparkles, ChevronLeft, ChevronRight, X, Edit, Trash2, Search, ChevronDown, ChevronUp, MoreVertical, TrendingUp } from 'lucide-react';
import { generateLessonPlan } from '../services/geminiService';
import { PRICE_1ON1, PRICE_GROUP } from '../constants';

interface SessionLogProps {
  sessions: Session[];
  students: Student[];
  onAddSession: (session: Omit<Session, 'id'>) => void;
  onUpdateSession: (session: Session) => void;
  onDeleteSession: (id: string) => void;
  onUpdateStudent: (student: Student) => void; // Added to sync progress
  onSelectStudent?: (student: Student) => void;
}

const SessionLog: React.FC<SessionLogProps> = ({ sessions, students, onAddSession, onUpdateSession, onDeleteSession, onUpdateStudent, onSelectStudent }) => {
  const [currentMonth, setCurrentMonth] = useState(new Date());

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);

  // Form State
  const [selectedStudents, setSelectedStudents] = useState<string[]>([]);
  const [studentStatuses, setStudentStatuses] = useState<Record<string, AttendanceStatus>>({});

  const [date, setDate] = useState('');
  const [time, setTime] = useState('14:00');
  const [topic, setTopic] = useState('');
  const [sessionType, setSessionType] = useState<ClassType>(ClassType.OneOnOne);
  const [notes, setNotes] = useState('');

  // Progress Editing State
  const [progressModalOpen, setProgressModalOpen] = useState(false);
  const [currentProgressStudentId, setCurrentProgressStudentId] = useState<string | null>(null);
  const [tempProgress, setTempProgress] = useState<Record<string, Partial<SkillProgress>>>({}); // Keyed by studentId

  // Dropdown UI State
  const [isStudentDropdownOpen, setIsStudentDropdownOpen] = useState(false);
  const [studentSearch, setStudentSearch] = useState('');

  // AI State
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [generatedPlan, setGeneratedPlan] = useState('');

  // Filter students for dropdown
  const filteredStudents = students.filter(s => 
    s.status === 'Active' && 
    s.name.toLowerCase().includes(studentSearch.toLowerCase())
  );

  // Calendar Logic
  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const days = new Date(year, month + 1, 0).getDate();
    const firstDay = new Date(year, month, 1).getDay();
    return { days, firstDay, year, month };
  };

  const { days, firstDay, year, month } = getDaysInMonth(currentMonth);

  const prevMonth = () => setCurrentMonth(new Date(year, month - 1, 1));
  const nextMonth = () => setCurrentMonth(new Date(year, month + 1, 1));

  const openAddModal = (day?: number) => {
    resetForm();
    if (day) {
        const m = month + 1;
        const dateStr = `${year}-${m < 10 ? '0' + m : m}-${day < 10 ? '0' + day : day}`;
        setDate(dateStr);
    } else {
        setDate(new Date().toISOString().split('T')[0]);
    }
    setEditingSessionId(null);
    setIsModalOpen(true);
  };

  const openEditModal = (session: Session) => {
    setEditingSessionId(session.id);
    setSelectedStudents(session.studentIds);

    // Convert array of statuses to map for easy form handling
    const statusMap: Record<string, AttendanceStatus> = {};
    if (session.studentStatuses) {
        session.studentStatuses.forEach(s => statusMap[s.studentId] = s.status);
    } else {
        // Backwards compatibility or default
        session.studentIds.forEach(id => statusMap[id] = session.status);
    }
    setStudentStatuses(statusMap);

    setDate(new Date(session.date).toISOString().split('T')[0]);
    setTime(new Date(session.date).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }));
    setTopic(session.topic);
    setSessionType(session.type);
    setNotes(session.notes);
    setGeneratedPlan('');
    setTempProgress({}); // Clear temp progress on edit load (could load from history if needed)
    setIsModalOpen(true);
  };

  const handleStudentToggle = (id: string) => {
    let newSelected = [];
    if (selectedStudents.includes(id)) {
      newSelected = selectedStudents.filter(s => s !== id);
      // Remove status entry
      const newStatuses = { ...studentStatuses };
      delete newStatuses[id];
      setStudentStatuses(newStatuses);
    } else {
      if (selectedStudents.length >= 2) return; // Limit to 2
      newSelected = [...selectedStudents, id];
      // Add default status
      setStudentStatuses({ ...studentStatuses, [id]: AttendanceStatus.Present });
    }
    setSelectedStudents(newSelected);

    // Auto switch type based on count
    if (newSelected.length === 2) setSessionType(ClassType.Group);
    else if (newSelected.length === 1) setSessionType(ClassType.OneOnOne);
  };

  const handleStatusChange = (studentId: string, status: AttendanceStatus) => {
      setStudentStatuses({ ...studentStatuses, [studentId]: status });
  }

  // --- Progress Handling ---

  const openProgressModal = (studentId: string) => {
      setCurrentProgressStudentId(studentId);

      // If we already have edited progress in this session for this student, load it.
      if (tempProgress[studentId]) {
          // It's already loaded in state
      } else {
          // Otherwise, find the student's latest progress to use as a baseline
          const s = students.find(st => st.id === studentId);
          const latest = s?.progressHistory && s.progressHistory.length > 0 
              ? s.progressHistory[s.progressHistory.length - 1]
              : { reading: 50, writing: 50, listening: 50, speaking: 50, notes: '' };

          setTempProgress(prev => ({
              ...prev,
              [studentId]: {
                  reading: latest.reading,
                  writing: latest.writing,
                  listening: latest.listening,
                  speaking: latest.speaking,
                  notes: '', // Start with blank note for new session
              }
          }));
      }
      setProgressModalOpen(true);
  };

  const updateTempProgress = (field: keyof SkillProgress, value: any) => {
      if (!currentProgressStudentId) return;
      setTempProgress(prev => ({
          ...prev,
          [currentProgressStudentId]: {
              ...prev[currentProgressStudentId],
              [field]: value
          }
      }));
  };

  // --- End Progress Handling ---

  const handleGeneratePlan = async () => {
    if (!topic || selectedStudents.length === 0) return;
    setIsGeneratingPlan(true);
    const studentNames = students.filter(s => selectedStudents.includes(s.id)).map(s => s.name);
    const plan = await generateLessonPlan(topic, studentNames, 60);
    setGeneratedPlan(plan);
    setNotes(prev => prev + (prev ? '\n\n' : '') + "Lesson Plan: " + topic);
    setIsGeneratingPlan(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedStudents.length === 0) return;

    const pricePerStudent = sessionType === ClassType.OneOnOne ? PRICE_1ON1 : PRICE_GROUP;
    const totalPrice = pricePerStudent * selectedStudents.length;

    // Construct studentStatuses array
    const studentStatusesArray: StudentSessionStatus[] = selectedStudents.map(id => ({
        studentId: id,
        status: studentStatuses[id] || AttendanceStatus.Present
    }));

    // Determine overall status
    const overallStatus = AttendanceStatus.Present;

    const sessionData = {
      studentIds: selectedStudents,
      date: `${date}T${time}:00`,
      durationMinutes: 60,
      status: overallStatus,
      studentStatuses: studentStatusesArray,
      type: sessionType,
      topic,
      notes: generatedPlan ? `${notes}\n\n--- AI Plan ---\n${generatedPlan}` : notes,
      price: totalPrice
    };

    if (editingSessionId) {
        onUpdateSession({ ...sessionData, id: editingSessionId });
    } else {
        onAddSession(sessionData);
    }

    // --- Sync Progress ---
    // If we have tempProgress for any of the selected students, save it to their history
    selectedStudents.forEach(stuId => {
        const pending = tempProgress[stuId];
        if (pending) {
            const student = students.find(s => s.id === stuId);
            if (student) {
                const newEntry: SkillProgress = {
                    id: `ph${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
                    date: date, // Use session date
                    reading: pending.reading || 50,
                    writing: pending.writing || 50,
                    listening: pending.listening || 50,
                    speaking: pending.speaking || 50,
                    notes: pending.notes || `Progress note from session: ${topic}`
                };

                const updatedHistory = [...(student.progressHistory || []), newEntry]
                    .sort((a,b) => new Date(a.date).getTime() - new Date(b.date).getTime());

                onUpdateStudent({
                    ...student,
                    progressHistory: updatedHistory
                });
            }
        }
    });

    setIsModalOpen(false);
    resetForm();
  };

  const handleDelete = () => {
    if (editingSessionId && window.confirm("Delete this session?")) {
        onDeleteSession(editingSessionId);
        setIsModalOpen(false);
    }
  }

  const resetForm = () => {
    setSelectedStudents([]);
    setStudentStatuses({});
    setTopic('');
    setNotes('');
    setGeneratedPlan('');
    setSessionType(ClassType.OneOnOne);
    setEditingSessionId(null);
    setStudentSearch('');
    setIsStudentDropdownOpen(false);
    setTempProgress({});
    setCurrentProgressStudentId(null);
  };

  const renderCalendar = () => {
    const blanks = Array(firstDay).fill(null);
    const daySlots = Array.from({ length: days }, (_, i) => i + 1);
    const allSlots = [...blanks, ...daySlots];

    return (
        <div className="grid grid-cols-7 gap-px bg-slate-200 rounded-lg overflow-hidden border border-slate-200">
            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => (
                <div key={d} className="bg-slate-50 p-2 text-center text-xs font-semibold text-slate-500 uppercase">
                    {d}
                </div>
            ))}
            {allSlots.map((day, index) => {
                if (!day) return <div key={`blank-${index}`} className="bg-white h-32 md:h-40" />;

                // Find sessions for this day
                const currentDayStr = `${year}-${(month + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
                const daySessions = sessions.filter(s => s.date.startsWith(currentDayStr));

                return (
                    <div 
                        key={day} 
                        onClick={() => openAddModal(day as number)}
                        className="bg-white h-32 md:h-40 p-2 border-t border-slate-50 hover:bg-slate-50 transition-colors cursor-pointer overflow-y-auto"
                    >
                        <div className="flex justify-between items-start mb-1">
                            <span className={`text-sm font-semibold ${
                                new Date().toDateString() === new Date(year, month, day as number).toDateString() 
                                ? 'bg-indigo-600 text-white w-6 h-6 flex items-center justify-center rounded-full' 
                                : 'text-slate-700'
                            }`}>
                                {day}
                            </span>
                        </div>
                        <div className="space-y-1">
                            {daySessions.map(session => (
                                <div 
                                    key={session.id}
                                    onClick={(e) => { e.stopPropagation(); openEditModal(session); }}
                                    className={`text-[10px] p-1.5 rounded border border-l-2 shadow-sm cursor-pointer hover:opacity-80 transition-opacity ${
                                        session.type === ClassType.OneOnOne 
                                        ? 'bg-blue-50 border-blue-100 border-l-blue-500 text-blue-700' 
                                        : 'bg-orange-50 border-orange-100 border-l-orange-500 text-orange-700'
                                    }`}
                                >
                                    <div className="font-semibold truncate">{session.topic}</div>
                                    <div className="text-xs opacity-75">
                                        {new Date(session.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                    </div>
                                    <div className="truncate opacity-75">
                                        {session.studentIds.map(sid => students.find(s => s.id === sid)?.name.split(' ')[0]).join(', ')}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                );
            })}
        </div>
    );
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-4">
            <h2 className="text-xl font-bold text-slate-800">
                {currentMonth.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
            </h2>
            <div className="flex items-center bg-white rounded-lg border border-slate-200 shadow-sm">
                <button onClick={prevMonth} className="p-1.5 hover:bg-slate-50 text-slate-600"><ChevronLeft className="w-5 h-5" /></button>
                <div className="w-px h-6 bg-slate-200"></div>
                <button onClick={nextMonth} className="p-1.5 hover:bg-slate-50 text-slate-600"><ChevronRight className="w-5 h-5" /></button>
            </div>
        </div>
        <button
          onClick={() => openAddModal()}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
        >
          <Calendar className="w-4 h-4" />
          Log Session
        </button>
      </div>

      {renderCalendar()}

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto animate-in zoom-in-95 duration-200 relative">
                <div className="flex justify-between items-center p-6 border-b border-slate-100">
                    <h3 className="text-lg font-bold text-slate-800">
                        {editingSessionId ? 'Edit Session' : 'Log New Session'}
                    </h3>
                    <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                        <X className="w-5 h-5" />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="p-6 space-y-4">
                    <div className="grid grid-cols-1 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">Session Type</label>
                            <select
                                value={sessionType}
                                onChange={e => setSessionType(e.target.value as ClassType)}
                                className="w-full p-2 border rounded-md"
                            >
                                <option value={ClassType.OneOnOne}>One-on-One</option>
                                <option value={ClassType.Group}>One-on-Two (Group)</option>
                            </select>
                        </div>

                        {/* Student Dropdown Selector */}
                        <div className="relative">
                            <label className="block text-sm font-medium text-slate-700 mb-2">Select Students</label>

                            {/* Selected Students Chips */}
                            <div className="flex flex-wrap gap-2 mb-2">
                                {selectedStudents.map(id => {
                                    const s = students.find(student => student.id === id);
                                    if(!s) return null;
                                    return (
                                        <div key={id} className="bg-indigo-50 border border-indigo-200 text-indigo-700 px-3 py-1 rounded-full text-sm flex items-center gap-2">
                                            {s.name}
                                            <button type="button" onClick={() => handleStudentToggle(id)}><X className="w-3 h-3" /></button>
                                        </div>
                                    )
                                })}
                            </div>

                            <button 
                                type="button"
                                onClick={() => setIsStudentDropdownOpen(!isStudentDropdownOpen)}
                                className="w-full p-2 border rounded-md flex justify-between items-center bg-white hover:bg-slate-50 text-left"
                            >
                                <span className="text-slate-500 text-sm">
                                    {selectedStudents.length === 0 ? "Search and select students..." : `${selectedStudents.length} selected`}
                                </span>
                                {isStudentDropdownOpen ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
                            </button>

                            {isStudentDropdownOpen && (
                                <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-lg z-20 max-h-60 overflow-hidden flex flex-col">
                                    <div className="p-2 border-b border-slate-100">
                                        <div className="relative">
                                            <Search className="absolute left-2 top-1/2 transform -translate-y-1/2 w-4 h-4 text-slate-400" />
                                            <input 
                                                autoFocus
                                                type="text" 
                                                placeholder="Search name..."
                                                className="w-full pl-8 pr-2 py-1.5 text-sm bg-slate-50 rounded-md focus:outline-none"
                                                value={studentSearch}
                                                onChange={e => setStudentSearch(e.target.value)}
                                            />
                                        </div>
                                    </div>
                                    <div className="overflow-y-auto flex-1 p-1">
                                        {filteredStudents.length === 0 && <div className="p-2 text-center text-xs text-slate-400">No active students found.</div>}
                                        {filteredStudents.map(s => (
                                            <button
                                                key={s.id}
                                                type="button"
                                                onClick={() => handleStudentToggle(s.id)}
                                                disabled={!selectedStudents.includes(s.id) && selectedStudents.length >= 2}
                                                className={`w-full text-left px-3 py-2 text-sm rounded-md flex items-center justify-between ${
                                                    selectedStudents.includes(s.id) ? 'bg-indigo-50 text-indigo-700' : 'hover:bg-slate-50 text-slate-700 disabled:opacity-50'
                                                }`}
                                            >
                                                <span>{s.name}</span>
                                                {selectedStudents.includes(s.id) && <CheckCircle className="w-4 h-4" />}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Attendance Status Per Student */}
                    {selectedStudents.length > 0 && (
                        <div className="bg-slate-50 p-3 rounded-lg border border-slate-100 space-y-2">
                            <label className="block text-xs font-semibold text-slate-500 uppercase">Attendance & Progress</label>
                            {selectedStudents.map(id => {
                                const s = students.find(student => student.id === id);
                                if (!s) return null;
                                const hasProgress = !!tempProgress[id];
                                return (
                                    <div key={id} className="flex justify-between items-center gap-2">
                                        <div className="flex items-center gap-2 overflow-hidden flex-1">
                                             <span className="text-sm font-medium text-slate-700 truncate">{s.name}</span>
                                             {hasProgress && <span className="bg-violet-100 text-violet-700 text-[10px] px-1.5 py-0.5 rounded-full flex items-center gap-1"><TrendingUp className="w-3 h-3"/> Updated</span>}
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <select 
                                                value={studentStatuses[id] || AttendanceStatus.Present}
                                                onChange={(e) => handleStatusChange(id, e.target.value as AttendanceStatus)}
                                                className={`text-sm p-1.5 rounded border ${
                                                    studentStatuses[id] === AttendanceStatus.Present ? 'bg-emerald-50 border-emerald-200 text-emerald-700' :
                                                    studentStatuses[id] === AttendanceStatus.Late ? 'bg-amber-50 border-amber-200 text-amber-700' :
                                                    'bg-red-50 border-red-200 text-red-700'
                                                }`}
                                            >
                                                {Object.values(AttendanceStatus).map(status => (
                                                    <option key={status} value={status}>{status}</option>
                                                ))}
                                            </select>
                                            <button 
                                                type="button" 
                                                onClick={() => openProgressModal(id)}
                                                className={`p-1.5 rounded transition-colors border ${hasProgress ? 'bg-violet-50 text-violet-600 border-violet-200' : 'text-slate-400 border-transparent hover:bg-slate-100'}`}
                                                title="Edit Progress & Notes"
                                            >
                                                <MoreVertical className="w-4 h-4" />
                                            </button>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}

                    <div className="grid grid-cols-2 gap-4">
                        <input
                            type="date"
                            value={date}
                            onChange={e => setDate(e.target.value)}
                            className="p-2 border rounded-md"
                            required
                        />
                        <input
                            type="time"
                            value={time}
                            onChange={e => setTime(e.target.value)}
                            className="p-2 border rounded-md"
                            required
                        />
                    </div>

                    <div className="flex gap-4">
                        <input
                            placeholder="Topic"
                            value={topic}
                            onChange={e => setTopic(e.target.value)}
                            className="flex-1 p-2 border rounded-md"
                            required
                        />
                    </div>

                    <div className="relative">
                        <textarea
                            placeholder="General session notes..."
                            value={notes}
                            onChange={e => setNotes(e.target.value)}
                            className="w-full p-2 border rounded-md"
                            rows={3}
                        />
                        <button
                            type="button"
                            disabled={!topic || selectedStudents.length === 0 || isGeneratingPlan}
                            onClick={handleGeneratePlan}
                            className="absolute bottom-2 right-2 text-xs flex items-center gap-1 bg-violet-100 text-violet-700 px-2 py-1 rounded-md hover:bg-violet-200 disabled:opacity-50"
                        >
                            <Sparkles className="w-3 h-3" />
                            {isGeneratingPlan ? 'Generating...' : 'AI Plan'}
                        </button>
                    </div>

                    {generatedPlan && (
                        <div className="bg-violet-50 p-3 rounded-md text-xs text-slate-700 max-h-40 overflow-y-auto whitespace-pre-wrap border border-violet-100">
                            <h4 className="font-semibold text-violet-800 mb-1">Generated Plan Preview:</h4>
                            {generatedPlan}
                        </div>
                    )}

                    <div className="flex justify-between pt-2">
                        {editingSessionId ? (
                            <button
                                type="button"
                                onClick={handleDelete}
                                className="flex items-center gap-2 text-red-600 hover:bg-red-50 px-3 py-2 rounded-md transition-colors"
                            >
                                <Trash2 className="w-4 h-4" />
                                Delete
                            </button>
                        ) : <div></div>}

                        <div className="flex gap-2">
                            <button 
                                type="button" 
                                onClick={() => setIsModalOpen(false)}
                                className="px-4 py-2 text-slate-600 hover:bg-slate-50 rounded-md"
                            >
                                Cancel
                            </button>
                            <button 
                                type="submit"
                                className="px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-700"
                            >
                                {editingSessionId ? 'Update Session' : 'Save Session'}
                            </button>
                        </div>
                    </div>
                </form>

                {/* Nested Modal for Progress Editing */}
                {progressModalOpen && currentProgressStudentId && (
                     <div className="absolute inset-0 z-[60] bg-white rounded-xl flex flex-col animate-in slide-in-from-bottom-2">
                        <div className="flex justify-between items-center p-4 border-b border-slate-100 bg-violet-50 rounded-t-xl">
                            <h3 className="font-bold text-violet-900 flex items-center gap-2">
                                <TrendingUp className="w-4 h-4" /> 
                                Progress: {students.find(s => s.id === currentProgressStudentId)?.name}
                            </h3>
                            <button onClick={() => setProgressModalOpen(false)} className="text-violet-400 hover:text-violet-700">
                                <X className="w-5 h-5" />
                            </button>
                        </div>
                        <div className="flex-1 p-6 overflow-y-auto">
                            <div className="grid grid-cols-2 gap-4 mb-6">
                                {[
                                    { label: 'Reading', key: 'reading', color: 'bg-blue-100 text-blue-700' },
                                    { label: 'Writing', key: 'writing', color: 'bg-emerald-100 text-emerald-700' },
                                    { label: 'Listening', key: 'listening', color: 'bg-amber-100 text-amber-700' },
                                    { label: 'Speaking', key: 'speaking', color: 'bg-violet-100 text-violet-700' },
                                ].map((field) => (
                                    <div key={field.key}>
                                        <label className={`block text-[10px] uppercase font-bold mb-1 px-2 py-0.5 rounded-full w-fit ${field.color}`}>
                                            {field.label}
                                        </label>
                                        <input 
                                            type="number" 
                                            min="0" max="100"
                                            value={tempProgress[currentProgressStudentId]?.[field.key as keyof SkillProgress] || 0}
                                            onChange={e => updateTempProgress(field.key as keyof SkillProgress, parseInt(e.target.value) || 0)}
                                            className="w-full p-2 rounded-md border text-sm text-center font-semibold"
                                        />
                                    </div>
                                ))}
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-slate-500 mb-1">Student-Specific Note</label>
                                <textarea 
                                    value={tempProgress[currentProgressStudentId]?.notes || ''}
                                    onChange={e => updateTempProgress('notes', e.target.value)}
                                    placeholder="Specific achievements or struggles today..."
                                    className="w-full p-2 rounded-md border text-sm"
                                    rows={3}
                                />
                            </div>
                        </div>
                        <div className="p-4 border-t border-slate-100 flex justify-end">
                             <button 
                                type="button" 
                                onClick={() => setProgressModalOpen(false)}
                                className="px-4 py-2 bg-violet-600 text-white rounded-md hover:bg-violet-700 text-sm font-medium"
                            >
                                Done
                            </button>
                        </div>
                     </div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

export default SessionLog;

import React, { useState, useEffect } from 'react';
import { Session, Student, AttendanceStatus, ClassType, StudentSessionStatus, SkillProgress } from '../types';
import { Calendar, Clock, CheckCircle, XCircle, AlertCircle, Sparkles, ChevronLeft, ChevronRight, X, Edit, Trash2, Search, ChevronDown, ChevronUp, MoreVertical, TrendingUp } from 'lucide-react';
import { generateLessonPlan } from '../services/geminiService';
import { PRICE_1ON1, PRICE_GROUP } from '../constants';

interface SessionLogProps {
  sessions: Session[];
  students: Student[];
  onAddSession: (session: Omit<Session, 'id'>) => void;
  onUpdateSession: (session: Session) => void;
  onDeleteSession: (id: string) => void;
  onUpdateStudent: (student: Student) => void; // Added to sync progress
  onSelectStudent?: (student: Student) => void;
}

const SessionLog: React.FC<SessionLogProps> = ({ sessions, students, onAddSession, onUpdateSession, onDeleteSession, onUpdateStudent, onSelectStudent }) => {
  const [currentMonth, setCurrentMonth] = useState(new Date());

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);

  // Form State
  const [selectedStudents, setSelectedStudents] = useState<string[]>([]);
  const [studentStatuses, setStudentStatuses] = useState<Record<string, AttendanceStatus>>({});

  const [date, setDate] = useState('');
  const [time, setTime] = useState('14:00');
  const [topic, setTopic] = useState('');
  const [sessionType, setSessionType] = useState<ClassType>(ClassType.OneOnOne);
  const [notes, setNotes] = useState('');

  // Progress Editing State
  const [progressModalOpen, setProgressModalOpen] = useState(false);
  const [currentProgressStudentId, setCurrentProgressStudentId] = useState<string | null>(null);
  const [tempProgress, setTempProgress] = useState<Record<string, Partial<SkillProgress>>>({}); // Keyed by studentId

  // Dropdown UI State
  const [isStudentDropdownOpen, setIsStudentDropdownOpen] = useState(false);
  const [studentSearch, setStudentSearch] = useState('');

  // AI State
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [generatedPlan, setGeneratedPlan] = useState('');

  // Filter students for dropdown
  const filteredStudents = students.filter(s => 
    s.status === 'Active' && 
    s.name.toLowerCase().includes(studentSearch.toLowerCase())
  );

  // Calendar Logic
  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const days = new Date(year, month + 1, 0).getDate();
    const firstDay = new Date(year, month, 1).getDay();
    return { days, firstDay, year, month };
  };

  const { days, firstDay, year, month } = getDaysInMonth(currentMonth);

  const prevMonth = () => setCurrentMonth(new Date(year, month - 1, 1));
  const nextMonth = () => setCurrentMonth(new Date(year, month + 1, 1));

  const openAddModal = (day?: number) => {
    resetForm();
    if (day) {
        const m = month + 1;
        const dateStr = `${year}-${m < 10 ? '0' + m : m}-${day < 10 ? '0' + day : day}`;
        setDate(dateStr);
    } else {
        setDate(new Date().toISOString().split('T')[0]);
    }
    setEditingSessionId(null);
    setIsModalOpen(true);
  };

  const openEditModal = (session: Session) => {
    setEditingSessionId(session.id);
    setSelectedStudents(session.studentIds);

    // Convert array of statuses to map for easy form handling
    const statusMap: Record<string, AttendanceStatus> = {};
    if (session.studentStatuses) {
        session.studentStatuses.forEach(s => statusMap[s.studentId] = s.status);
    } else {
        // Backwards compatibility or default
        session.studentIds.forEach(id => statusMap[id] = session.status);
    }
    setStudentStatuses(statusMap);

    setDate(new Date(session.date).toISOString().split('T')[0]);
    setTime(new Date(session.date).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }));
    setTopic(session.topic);
    setSessionType(session.type);
    setNotes(session.notes);
    setGeneratedPlan('');
    setTempProgress({}); // Clear temp progress on edit load (could load from history if needed)
    setIsModalOpen(true);
  };

  const handleStudentToggle = (id: string) => {
    let newSelected = [];
    if (selectedStudents.includes(id)) {
      newSelected = selectedStudents.filter(s => s !== id);
      // Remove status entry
      const newStatuses = { ...studentStatuses };
      delete newStatuses[id];
      setStudentStatuses(newStatuses);
    } else {
      if (selectedStudents.length >= 2) return; // Limit to 2
      newSelected = [...selectedStudents, id];
      // Add default status
      setStudentStatuses({ ...studentStatuses, [id]: AttendanceStatus.Present });
    }
    setSelectedStudents(newSelected);

    // Auto switch type based on count
    if (newSelected.length === 2) setSessionType(ClassType.Group);
    else if (newSelected.length === 1) setSessionType(ClassType.OneOnOne);
  };

  const handleStatusChange = (studentId: string, status: AttendanceStatus) => {
      setStudentStatuses({ ...studentStatuses, [studentId]: status });
  }

  // --- Progress Handling ---

  const openProgressModal = (studentId: string) => {
      setCurrentProgressStudentId(studentId);

      // If we already have edited progress in this session for this student, load it.
      if (tempProgress[studentId]) {
          // It's already loaded in state
      } else {
          // Otherwise, find the student's latest progress to use as a baseline
          const s = students.find(st => st.id === studentId);
          const latest = s?.progressHistory && s.progressHistory.length > 0 
              ? s.progressHistory[s.progressHistory.length - 1]
              : { reading: 50, writing: 50, listening: 50, speaking: 50, notes: '' };

          setTempProgress(prev => ({
              ...prev,
              [studentId]: {
                  reading: latest.reading,
                  writing: latest.writing,
                  listening: latest.listening,
                  speaking: latest.speaking,
                  notes: '', // Start with blank note for new session
              }
          }));
      }
      setProgressModalOpen(true);
  };

  const updateTempProgress = (field: keyof SkillProgress, value: any) => {
      if (!currentProgressStudentId) return;
      setTempProgress(prev => ({
          ...prev,
          [currentProgressStudentId]: {
              ...prev[currentProgressStudentId],
              [field]: value
          }
      }));
  };

  // --- End Progress Handling ---

  const handleGeneratePlan = async () => {
    if (!topic || selectedStudents.length === 0) return;
    setIsGeneratingPlan(true);
    const studentNames = students.filter(s => selectedStudents.includes(s.id)).map(s => s.name);
    const plan = await generateLessonPlan(topic, studentNames, 60);
    setGeneratedPlan(plan);
    setNotes(prev => prev + (prev ? '\n\n' : '') + "Lesson Plan: " + topic);
    setIsGeneratingPlan(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedStudents.length === 0) return;

    const pricePerStudent = sessionType === ClassType.OneOnOne ? PRICE_1ON1 : PRICE_GROUP;
    const totalPrice = pricePerStudent * selectedStudents.length;

    // Construct studentStatuses array
    const studentStatusesArray: StudentSessionStatus[] = selectedStudents.map(id => ({
        studentId: id,
        status: studentStatuses[id] || AttendanceStatus.Present
    }));

    // Determine overall status
    const overallStatus = AttendanceStatus.Present;

    const sessionData = {
      studentIds: selectedStudents,
      date: `${date}T${time}:00`,
      durationMinutes: 60,
      status: overallStatus,
      studentStatuses: studentStatusesArray,
      type: sessionType,
      topic,
      notes: generatedPlan ? `${notes}\n\n--- AI Plan ---\n${generatedPlan}` : notes,
      price: totalPrice
    };

    if (editingSessionId) {
        onUpdateSession({ ...sessionData, id: editingSessionId });
    } else {
        onAddSession(sessionData);
    }

    // --- Sync Progress ---
    // If we have tempProgress for any of the selected students, save it to their history
    selectedStudents.forEach(stuId => {
        const pending = tempProgress[stuId];
        if (pending) {
            const student = students.find(s => s.id === stuId);
            if (student) {
                const newEntry: SkillProgress = {
                    id: `ph${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
                    date: date, // Use session date
                    reading: pending.reading || 50,
                    writing: pending.writing || 50,
                    listening: pending.listening || 50,
                    speaking: pending.speaking || 50,
                    notes: pending.notes || `Progress note from session: ${topic}`
                };

                const updatedHistory = [...(student.progressHistory || []), newEntry]
                    .sort((a,b) => new Date(a.date).getTime() - new Date(b.date).getTime());

                onUpdateStudent({
                    ...student,
                    progressHistory: updatedHistory
                });
            }
        }
    });

    setIsModalOpen(false);
    resetForm();
  };

  const handleDelete = () => {
    if (editingSessionId && window.confirm("Delete this session?")) {
        onDeleteSession(editingSessionId);
        setIsModalOpen(false);
    }
  }

  const resetForm = () => {
    setSelectedStudents([]);
    setStudentStatuses({});
    setTopic('');
    setNotes('');
    setGeneratedPlan('');
    setSessionType(ClassType.OneOnOne);
    setEditingSessionId(null);
    setStudentSearch('');
    setIsStudentDropdownOpen(false);
    setTempProgress({});
    setCurrentProgressStudentId(null);
  };

  const renderCalendar = () => {
    const blanks = Array(firstDay).fill(null);
    const daySlots = Array.from({ length: days }, (_, i) => i + 1);
    const allSlots = [...blanks, ...daySlots];

    return (
        <div className="grid grid-cols-7 gap-px bg-slate-200 rounded-lg overflow-hidden border border-slate-200">
            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => (
                <div key={d} className="bg-slate-50 p-2 text-center text-xs font-semibold text-slate-500 uppercase">
                    {d}
                </div>
            ))}
            {allSlots.map((day, index) => {
                if (!day) return <div key={`blank-${index}`} className="bg-white h-32 md:h-40" />;

                // Find sessions for this day
                const currentDayStr = `${year}-${(month + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
                const daySessions = sessions.filter(s => s.date.startsWith(currentDayStr));

                return (
                    <div 
                        key={day} 
                        onClick={() => openAddModal(day as number)}
                        className="bg-white h-32 md:h-40 p-2 border-t border-slate-50 hover:bg-slate-50 transition-colors cursor-pointer overflow-y-auto"
                    >
                        <div className="flex justify-between items-start mb-1">
                            <span className={`text-sm font-semibold ${
                                new Date().toDateString() === new Date(year, month, day as number).toDateString() 
                                ? 'bg-indigo-600 text-white w-6 h-6 flex items-center justify-center rounded-full' 
                                : 'text-slate-700'
                            }`}>
                                {day}
                            </span>
                        </div>
                        <div className="space-y-1">
                            {daySessions.map(session => (
                                <div 
                                    key={session.id}
                                    onClick={(e) => { e.stopPropagation(); openEditModal(session); }}
                                    className={`text-[10px] p-1.5 rounded border border-l-2 shadow-sm cursor-pointer hover:opacity-80 transition-opacity ${
                                        session.type === ClassType.OneOnOne 
                                        ? 'bg-blue-50 border-blue-100 border-l-blue-500 text-blue-700' 
                                        : 'bg-orange-50 border-orange-100 border-l-orange-500 text-orange-700'
                                    }`}
                                >
                                    <div className="font-semibold truncate">{session.topic}</div>
                                    <div className="text-xs opacity-75">
                                        {new Date(session.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                    </div>
                                    <div className="truncate opacity-75">
                                        {session.studentIds.map(sid => students.find(s => s.id === sid)?.name.split(' ')[0]).join(', ')}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                );
            })}
        </div>
    );
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-4">
            <h2 className="text-xl font-bold text-slate-800">
                {currentMonth.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
            </h2>
            <div className="flex items-center bg-white rounded-lg border border-slate-200 shadow-sm">
                <button onClick={prevMonth} className="p-1.5 hover:bg-slate-50 text-slate-600"><ChevronLeft className="w-5 h-5" /></button>
                <div className="w-px h-6 bg-slate-200"></div>
                <button onClick={nextMonth} className="p-1.5 hover:bg-slate-50 text-slate-600"><ChevronRight className="w-5 h-5" /></button>
            </div>
        </div>
        <button
          onClick={() => openAddModal()}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
        >
          <Calendar className="w-4 h-4" />
          Log Session
        </button>
      </div>

      {renderCalendar()}

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto animate-in zoom-in-95 duration-200 relative">
                <div className="flex justify-between items-center p-6 border-b border-slate-100">
                    <h3 className="text-lg font-bold text-slate-800">
                        {editingSessionId ? 'Edit Session' : 'Log New Session'}
                    </h3>
                    <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                        <X className="w-5 h-5" />
                    </button>
