                                                className={`w-full text-left px-3 py-2 text-sm rounded-md flex items-center justify-between ${
                                                    selectedStudents.includes(s.id) ? 'bg-indigo-50 text-indigo-700' : 'hover:bg-slate-50 text-slate-700 disabled:opacity-50'
                                                }`}
                                            >
                                                <span>{s.name}</span>
                                                {selectedStudents.includes(s.id) && <CheckCircle className="w-4 h-4" />}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Attendance Status Per Student */}
                    {selectedStudents.length > 0 && (
                        <div className="bg-slate-50 p-3 rounded-lg border border-slate-100 space-y-2">
                            <label className="block text-xs font-semibold text-slate-500 uppercase">Attendance & Progress</label>
                            {selectedStudents.map(id => {
                                const s = students.find(student => student.id === id);
                                if (!s) return null;
                                const hasProgress = !!tempProgress[id];
                                return (
                                    <div key={id} className="flex justify-between items-center gap-2">
                                        <div className="flex items-center gap-2 overflow-hidden flex-1">
                                             <span className="text-sm font-medium text-slate-700 truncate">{s.name}</span>
                                             {hasProgress && <span className="bg-violet-100 text-violet-700 text-[10px] px-1.5 py-0.5 rounded-full flex items-center gap-1"><TrendingUp className="w-3 h-3"/> Updated</span>}
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <select 
                                                value={studentStatuses[id] || AttendanceStatus.Present}
                                                onChange={(e) => handleStatusChange(id, e.target.value as AttendanceStatus)}
                                                className={`text-sm p-1.5 rounded border ${
                                                    studentStatuses[id] === AttendanceStatus.Present ? 'bg-emerald-50 border-emerald-200 text-emerald-700' :
                                                    studentStatuses[id] === AttendanceStatus.Late ? 'bg-amber-50 border-amber-200 text-amber-700' :
                                                    'bg-red-50 border-red-200 text-red-700'
                                                }`}
                                            >
                                                {Object.values(AttendanceStatus).map(status => (
                                                    <option key={status} value={status}>{status}</option>
                                                ))}
                                            </select>
                                            <button 
                                                type="button" 
                                                onClick={() => openProgressModal(id)}
                                                className={`p-1.5 rounded transition-colors border ${hasProgress ? 'bg-violet-50 text-violet-600 border-violet-200' : 'text-slate-400 border-transparent hover:bg-slate-100'}`}
                                                title="Edit Progress & Notes"
                                            >
                                                <MoreVertical className="w-4 h-4" />
                                            </button>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}

                    <div className="grid grid-cols-2 gap-4">
                        <input
                            type="date"
                            value={date}
                            onChange={e => setDate(e.target.value)}
                            className="p-2 border rounded-md"
                            required
                        />
                        <input
                            type="time"
                            value={time}
                            onChange={e => setTime(e.target.value)}
                            className="p-2 border rounded-md"
                            required
                        />
                    </div>

                    <div className="flex gap-4">
                        <input
                            placeholder="Topic"
                            value={topic}
                            onChange={e => setTopic(e.target.value)}
                            className="flex-1 p-2 border rounded-md"
                            required
                        />
                    </div>

                    <div className="relative">
                        <textarea
                            placeholder="General session notes..."
                            value={notes}
                            onChange={e => setNotes(e.target.value)}
                            className="w-full p-2 border rounded-md"
                            rows={3}
                        />
                        <button
                            type="button"
                            disabled={!topic || selectedStudents.length === 0 || isGeneratingPlan}
                            onClick={handleGeneratePlan}
                            className="absolute bottom-2 right-2 text-xs flex items-center gap-1 bg-violet-100 text-violet-700 px-2 py-1 rounded-md hover:bg-violet-200 disabled:opacity-50"
                        >
                            <Sparkles className="w-3 h-3" />
                            {isGeneratingPlan ? 'Generating...' : 'AI Plan'}
                        </button>
                    </div>

                    {generatedPlan && (
                        <div className="bg-violet-50 p-3 rounded-md text-xs text-slate-700 max-h-40 overflow-y-auto whitespace-pre-wrap border border-violet-100">
                            <h4 className="font-semibold text-violet-800 mb-1">Generated Plan Preview:</h4>
                            {generatedPlan}
                        </div>
                    )}

                    <div className="flex justify-between pt-2">
                        {editingSessionId ? (
                            <button
                                type="button"
                                onClick={handleDelete}
                                className="flex items-center gap-2 text-red-600 hover:bg-red-50 px-3 py-2 rounded-md transition-colors"
                            >
                                <Trash2 className="w-4 h-4" />
                                Delete
                            </button>
                        ) : <div></div>}

                        <div className="flex gap-2">
                            <button 
                                type="button" 
                                onClick={() => setIsModalOpen(false)}
                                className="px-4 py-2 text-slate-600 hover:bg-slate-50 rounded-md"
                            >
                                Cancel
                            </button>
                            <button 
                                type="submit"
                                className="px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-700"
                            >
                                {editingSessionId ? 'Update Session' : 'Save Session'}
                            </button>
                        </div>
                    </div>
                </form>

                {/* Nested Modal for Progress Editing */}
                {progressModalOpen && currentProgressStudentId && (
                     <div className="absolute inset-0 z-[60] bg-white rounded-xl flex flex-col animate-in slide-in-from-bottom-2">
                        <div className="flex justify-between items-center p-4 border-b border-slate-100 bg-violet-50 rounded-t-xl">
                            <h3 className="font-bold text-violet-900 flex items-center gap-2">
                                <TrendingUp className="w-4 h-4" /> 
                                Progress: {students.find(s => s.id === currentProgressStudentId)?.name}
                            </h3>
                            <button onClick={() => setProgressModalOpen(false)} className="text-violet-400 hover:text-violet-700">
                                <X className="w-5 h-5" />
                            </button>
                        </div>
                        <div className="flex-1 p-6 overflow-y-auto">
                            <div className="grid grid-cols-2 gap-4 mb-6">
                                {(() => {
                                    const s = students.find(st => st.id === currentProgressStudentId);
                                    const latest = s?.progressHistory && s.progressHistory.length > 0
                                        ? s.progressHistory[s.progressHistory.length - 1]
                                        : null;

                                    return [
                                        { label: 'Reading', key: 'reading', color: 'bg-blue-100 text-blue-700' },
                                        { label: 'Writing', key: 'writing', color: 'bg-emerald-100 text-emerald-700' },
                                        { label: 'Listening', key: 'listening', color: 'bg-amber-100 text-amber-700' },
                                        { label: 'Speaking', key: 'speaking', color: 'bg-violet-100 text-violet-700' },
                                    ].map((field) => {
                                        const previousScore = latest ? latest[field.key as keyof SkillProgress] : null;
                                        return (
                                            <div key={field.key}>
                                                <div className="flex justify-between items-center mb-1.5">
                                                    <label className={`block text-[10px] uppercase font-bold px-2 py-0.5 rounded-full w-fit ${field.color}`}>
                                                        {field.label}
                                                    </label>
                                                    {previousScore !== null && (
                                                        <span className="text-[10px] text-slate-400 font-medium bg-slate-100 px-1.5 py-0.5 rounded">
                                                            Prev: {previousScore}
                                                        </span>
                                                    )}
                                                </div>
                                                <input 
                                                    type="number" 
                                                    min="0" max="100"
                                                    value={tempProgress[currentProgressStudentId]?.[field.key as keyof SkillProgress] || 0}
                                                    onChange={e => updateTempProgress(field.key as keyof SkillProgress, parseInt(e.target.value) || 0)}
                                                    className="w-full p-2 rounded-md border text-sm text-center font-semibold focus:ring-2 focus:ring-indigo-500 outline-none"
                                                />
                                            </div>
                                        );
                                    });
                                })()}
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-slate-500 mb-1">Student-Specific Note</label>
                                <textarea 
                                    value={tempProgress[currentProgressStudentId]?.notes || ''}
                                    onChange={e => updateTempProgress('notes', e.target.value)}
                                    placeholder="Specific achievements or struggles today..."
                                    className="w-full p-2 rounded-md border text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                                    rows={3}
                                />
                            </div>
                        </div>
                        <div className="p-4 border-t border-slate-100 flex justify-end">
                             <button 
                                type="button" 
                                onClick={() => setProgressModalOpen(false)}
                                className="px-4 py-2 bg-violet-600 text-white rounded-md hover:bg-violet-700 text-sm font-medium"
                            >
                                Done
                            </button>
                        </div>
                     </div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

export default SessionLog;

import React, { useState } from 'react';
import { Student, Session, Payment, AttendanceStatus, ClassType, ClassPackage, SkillProgress } from '../types';
import { X, Sparkles, PlusCircle, Edit2, Save, XCircle, TrendingUp, Activity, FileText, Trash2 } from 'lucide-react';
import { generateStudentReport } from '../services/geminiService';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer, LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend } from 'recharts';

interface StudentDetailProps {
  student: Student;
  sessions: Session[];
  payments: Payment[]; 
  onClose: () => void;
  onUpdatePayment: (studentId: string, amount: number) => void;
  onUpdateStudent: (student: Student) => void;
}

const StudentDetail: React.FC<StudentDetailProps> = ({ student, sessions, onClose, onUpdateStudent }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'progress' | 'history'>('overview');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  // Renew Package State
  const [isRenewing, setIsRenewing] = useState(false);
  const [renewType, setRenewType] = useState<ClassType>(ClassType.OneOnOne);
  const [renewClasses, setRenewClasses] = useState(10);
  const [renewCost, setRenewCost] = useState(400);

  // Edit Package State
  const [editingPackageIndex, setEditingPackageIndex] = useState<number | null>(null);
  const [editRemainingCount, setEditRemainingCount] = useState<number>(0);

  // Progress State
  const [newProgress, setNewProgress] = useState({
      reading: 50,
      writing: 50,
      listening: 50,
      speaking: 50,
      date: new Date().toISOString().split('T')[0],
      notes: ''
  });

  // Edit History Log State
  const [editingLogId, setEditingLogId] = useState<string | null>(null);
  const [editLogData, setEditLogData] = useState<SkillProgress | null>(null);

  const studentSessions = sessions.filter(s => s.studentIds.includes(student.id));
  const attendedCount = studentSessions.filter(s => s.status === AttendanceStatus.Present).length;
  const attendanceRate = studentSessions.length ? Math.round((attendedCount / studentSessions.length) * 100) : 0;

  // Charts Data
  const progressHistory = student.progressHistory || [];
  const latestProgress = progressHistory.length > 0 
      ? progressHistory[progressHistory.length - 1] 
      : { reading: 0, writing: 0, listening: 0, speaking: 0 };

  const radarData = [
    { subject: 'Reading', A: latestProgress.reading, fullMark: 100 },
    { subject: 'Writing', A: latestProgress.writing, fullMark: 100 },
    { subject: 'Listening', A: latestProgress.listening, fullMark: 100 },
    { subject: 'Speaking', A: latestProgress.speaking, fullMark: 100 },
  ];

  const handleGenerateReport = async () => {
    setIsGenerating(true);
    const report = await generateStudentReport(student, studentSessions.slice(0, 5));
    setAiReport(report);
    setIsGenerating(false);
  };

  const handleRenewPackage = (e: React.FormEvent) => {
      e.preventDefault();

      const newPackages = [...(student.packages || [])];
      const existingPackageIndex = newPackages.findIndex(p => p.type === renewType);

      if (existingPackageIndex >= 0) {
          newPackages[existingPackageIndex] = {
              ...newPackages[existingPackageIndex],
              total: newPackages[existingPackageIndex].total + renewClasses,
              active: true
          };
      } else {
          newPackages.push({
              type: renewType,
              total: renewClasses,
              active: true
          });
      }

      const newBalance = student.balance - renewCost;

      const newClassTypes = student.classTypes.includes(renewType) 
        ? student.classTypes 
        : [...student.classTypes, renewType];

      onUpdateStudent({
          ...student,
          packages: newPackages,
          balance: newBalance,
          classTypes: newClassTypes
      });

      setIsRenewing(false);
      setRenewClasses(10);
      setRenewCost(400);
  };

  const startEditing = (index: number, total: number, attended: number) => {
      setEditingPackageIndex(index);
      setEditRemainingCount(total - attended);
  };

  const savePackageEdit = (index: number, attended: number) => {
      if (!student.packages) return;

      const newPackages = [...student.packages];
      const newTotal = attended + editRemainingCount;

      newPackages[index] = {
          ...newPackages[index],
          total: newTotal
      };

      onUpdateStudent({
          ...student,
          packages: newPackages
      });
      setEditingPackageIndex(null);
  };

  const handleAddProgress = (e: React.FormEvent) => {
      e.preventDefault();
      const newEntry: SkillProgress = {
          id: `ph${Date.now()}`,
          date: newProgress.date,
          reading: Number(newProgress.reading),
          writing: Number(newProgress.writing),
          listening: Number(newProgress.listening),
          speaking: Number(newProgress.speaking),
          notes: newProgress.notes
      };

      // Sort by date after adding
      const updatedHistory = [...progressHistory, newEntry].sort((a,b) => new Date(a.date).getTime() - new Date(b.date).getTime());

      onUpdateStudent({
          ...student,
          progressHistory: updatedHistory
      });

      setNewProgress(prev => ({ ...prev, notes: '' }));
      // Optional: switch back to overview or clear form fully
  };

  const handleStartEditLog = (log: SkillProgress) => {
      setEditingLogId(log.id);
      setEditLogData({ ...log });
  };

  const handleDeleteProgress = (id: string) => {
      if (window.confirm('Are you sure you want to delete this log?')) {
          const updatedHistory = (student.progressHistory || []).filter(p => p.id !== id);
          onUpdateStudent({
              ...student,
              progressHistory: updatedHistory
          });
      }
  };

  const handleSaveEditLog = () => {
      if (!editLogData || !student.progressHistory) return;

      const updatedHistory = student.progressHistory.map(p => 
          p.id === editLogData.id ? editLogData : p
      ).sort((a,b) => new Date(a.date).getTime() - new Date(b.date).getTime());

      onUpdateStudent({
          ...student,
          progressHistory: updatedHistory
      });
      setEditingLogId(null);
      setEditLogData(null);
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex justify-end">
      <div className="w-full max-w-lg bg-slate-50 h-full shadow-2xl animate-in slide-in-from-right duration-300 flex flex-col">
        {/* Header */}
        <div className="bg-white p-6 border-b border-slate-200 flex justify-between items-start">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">{student.name}</h2>
            <div className="flex flex-wrap items-center gap-2 mt-2">
               <span className={`text-xs px-2 py-0.5 rounded-full border ${student.status === 'Active' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-slate-100 text-slate-600 border-slate-200'}`}>
                    {student.status}
               </span>
               {student.classTypes.map(type => (
                    <span key={type} className={`text-xs px-2 py-0.5 rounded-full ${type === ClassType.OneOnOne ? 'bg-blue-100 text-blue-700' : 'bg-orange-100 text-orange-700'}`}>
                        {type}
                    </span>
               ))}
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        {/* Tabs */}
        <div className="px-6 pt-4 flex gap-6 border-b border-slate-200 bg-white">
            <button 
                onClick={() => setActiveTab('overview')}
                className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'overview' ? 'text-indigo-600' : 'text-slate-500'}`}
            >
                Overview
                {activeTab === 'overview' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-600 rounded-t-full"></div>}
            </button>
            <button 
                onClick={() => setActiveTab('progress')}
                className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'progress' ? 'text-indigo-600' : 'text-slate-500'}`}
            >
                Progress
                {activeTab === 'progress' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-600 rounded-t-full"></div>}
            </button>
            <button 
                onClick={() => setActiveTab('history')}
                className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'history' ? 'text-indigo-600' : 'text-slate-500'}`}
            >
                History
                {activeTab === 'history' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-600 rounded-t-full"></div>}
            </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 space-y-6">
            {activeTab === 'overview' ? (
                <>
                    {/* Skills Radar Chart */}
                    <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                        <div className="flex items-center gap-2 mb-2">
                             <Activity className="w-4 h-4 text-indigo-600" />
                             <h3 className="font-semibold text-slate-800 text-sm">Skills Overview</h3>
                        </div>
                        <div className="h-56 w-full">
                            <ResponsiveContainer width="100%" height="100%">
                                <RadarChart cx="50%" cy="50%" outerRadius="70%" data={radarData}>
                                    <PolarGrid stroke="#e2e8f0" />
                                    <PolarAngleAxis dataKey="subject" tick={{ fill: '#64748b', fontSize: 11 }} />
                                    <PolarRadiusAxis angle={30} domain={[0, 100]} tick={false} axisLine={false} />
                                    <Radar name="Student" dataKey="A" stroke="#6366f1" fill="#6366f1" fillOpacity={0.5} />
                                    <Tooltip contentStyle={{ borderRadius: '8px', fontSize: '12px' }} />
                                </RadarChart>
                            </ResponsiveContainer>
                        </div>
                        <div className="text-center text-xs text-slate-400 mt-[-10px]">
                            Most recent assessment
                        </div>
                    </div>

                    {/* Renew / Add Package Section */}
                    <div className="bg-slate-100 rounded-xl p-4 border border-slate-200">
                        {!isRenewing ? (
                            <button 
                                onClick={() => setIsRenewing(true)}
                                className="w-full flex items-center justify-center gap-2 bg-white p-3 rounded-lg border border-slate-200 text-slate-700 font-medium hover:bg-slate-50 transition-colors"
                            >
                                <PlusCircle className="w-5 h-5 text-indigo-600" />
                                Renew Package / Add Credits
                            </button>
                        ) : (
                            <form onSubmit={handleRenewPackage} className="space-y-3 animate-in fade-in slide-in-from-top-2">
                                <div className="flex justify-between items-center mb-2">
                                    <h4 className="font-semibold text-slate-800">Add Sessions</h4>
                                    <button type="button" onClick={() => setIsRenewing(false)} className="text-slate-400 hover:text-slate-600"><X className="w-4 h-4" /></button>
                                </div>
                                <div>
                                    <label className="block text-xs font-medium text-slate-500 mb-1">Program Type</label>
                                    <select 
                                        value={renewType}
                                        onChange={e => setRenewType(e.target.value as ClassType)}
                                        className="w-full p-2 rounded-md border text-sm"
                                    >
                                        <option value={ClassType.OneOnOne}>One-on-One</option>
                                        <option value={ClassType.Group}>One-on-Two (Group)</option>
                                    </select>
                                </div>
                                <div className="grid grid-cols-2 gap-3">
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">No. of Sessions</label>
                                        <input 
                                            type="number" 
                                            min="1"
                                            value={renewClasses} 
                                            onChange={e => setRenewClasses(parseInt(e.target.value) || 0)}
                                            className="w-full p-2 rounded-md border text-sm"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-medium text-slate-500 mb-1">Amount Paid ($)</label>
                                        <input 
                                            type="number" 
                                            min="0"
                                            value={renewCost} 
                                            onChange={e => setRenewCost(parseFloat(e.target.value) || 0)}
                                            className="w-full p-2 rounded-md border text-sm"
                                        />
                                    </div>
                                </div>
                                <button type="submit" className="w-full bg-indigo-600 text-white py-2 rounded-lg text-sm font-medium hover:bg-indigo-700">
                                    Confirm Renewal
                                </button>
                            </form>
                        )}
                    </div>

                    {/* Stats Grid */}
                    <div className="grid grid-cols-2 gap-4">
                        <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                            <p className="text-xs text-slate-500 uppercase font-semibold">Attendance Rate</p>
                            <p className="text-xl font-bold text-slate-800 mt-1">{attendanceRate}%</p>
                        </div>
                        <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                            <p className="text-xs text-slate-500 uppercase font-semibold">Total Classes</p>
                            <p className="text-xl font-bold text-slate-800 mt-1">{attendedCount}</p>
                        </div>
                    </div>

                    {/* Class Packages */}
                    {student.packages && student.packages.length > 0 && (
                        <div className="space-y-3">
                            {student.packages.map((pkg, idx) => {
                                const attendedForType = studentSessions.filter(s => s.type === pkg.type && s.status === AttendanceStatus.Present).length;
                                const isEditing = editingPackageIndex === idx;
                                const progress = Math.min(100, Math.round((attendedForType / pkg.total) * 100));

                                return (
                                    <div key={idx} className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm transition-all">
                                        <div className="flex justify-between items-center mb-3">
                                            <h3 className="font-semibold text-slate-800">{pkg.type} Package</h3>
                                            {!isEditing && (
                                                <button 
                                                    onClick={() => startEditing(idx, pkg.total, attendedForType)}
                                                    className="p-1 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded"
                                                    title="Edit Remaining Classes"
                                                >
                                                    <Edit2 className="w-4 h-4" />
                                                </button>
                                            )}
                                        </div>

                                        {isEditing ? (
                                            <div className="space-y-3 bg-slate-50 p-3 rounded-lg border border-slate-100">
                                                <div className="flex justify-between text-sm text-slate-600">
                                                    <span>Attended:</span>
                                                    <span className="font-medium">{attendedForType}</span>
                                                </div>
                                                <div>
                                                    <label className="block text-xs font-medium text-slate-500 mb-1">Remaining Classes</label>
                                                    <input 
                                                        type="number"
                                                        min="0"
                                                        value={editRemainingCount}
                                                        onChange={(e) => setEditRemainingCount(parseInt(e.target.value) || 0)}
                                                        className="w-full p-2 border rounded-md text-sm"
                                                        autoFocus
                                                    />
                                                    <p className="text-[10px] text-slate-400 mt-1 text-right">New Total: {attendedForType + editRemainingCount}</p>
                                                </div>
                                                <div className="flex gap-2 justify-end">
                                                    <button 
                                                        onClick={() => setEditingPackageIndex(null)}
                                                        className="p-1.5 text-slate-500 hover:bg-slate-200 rounded"
                                                        title="Cancel"
                                                    >
                                                        <XCircle className="w-5 h-5" />
                                                    </button>
                                                    <button 
                                                        onClick={() => savePackageEdit(idx, attendedForType)}
                                                        className="p-1.5 text-emerald-600 hover:bg-emerald-50 rounded"
                                                        title="Save"
                                                    >
                                                        <Save className="w-5 h-5" />
                                                    </button>
                                                </div>
                                            </div>
                                        ) : (
                                            <>
                                                <div className="flex justify-between items-end mb-2">
                                                     <p className="text-sm font-medium text-slate-600">{attendedForType} / {pkg.total}</p>
                                                </div>
                                                <div className="w-full bg-slate-100 rounded-full h-2.5">
                                                    <div 
                                                        className={`h-2.5 rounded-full transition-all duration-500 ${pkg.type === ClassType.OneOnOne ? 'bg-blue-500' : 'bg-orange-500'}`} 
                                                        style={{ width: `${progress}%` }}
                                                    ></div>
                                                </div>
                                                {progress >= 100 ? (
                                                    <p className="text-xs text-red-500 mt-2 font-medium">Package complete! Time to renew.</p>
                                                ) : (
                                                    <p className="text-xs text-slate-400 mt-2">{pkg.total - attendedForType} classes remaining</p>
                                                )}
                                            </>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    )}

                    {/* AI Report Section */}
                    <div className="bg-violet-50 rounded-xl p-5 border border-violet-100">
                        <div className="flex justify-between items-center mb-3">
                            <h3 className="font-semibold text-violet-900 flex items-center gap-2">
                                <Sparkles className="w-4 h-4" /> AI Progress Report
                            </h3>
                            <button 
                                onClick={handleGenerateReport}
                                disabled={isGenerating}
                                className="text-xs bg-violet-200 text-violet-800 px-2 py-1 rounded hover:bg-violet-300 disabled:opacity-50 transition-colors"
                            >
                                {isGenerating ? 'Drafting...' : 'Generate New'}
                            </button>
                        </div>
                        {aiReport ? (
                            <div className="bg-white p-4 rounded-lg border border-violet-100 text-sm text-slate-600 leading-relaxed whitespace-pre-line">
                                {aiReport}
                            </div>
                        ) : (
                            <p className="text-sm text-violet-700/70">
                                Click generate to create a professional email update for {student.parentName}.
                            </p>
                        )}
                    </div>
                </>
            ) : activeTab === 'progress' ? (
                <div className="space-y-6">
                    {/* Progress Chart */}
                    <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                        <div className="flex items-center gap-2 mb-4">
                             <TrendingUp className="w-4 h-4 text-indigo-600" />
                             <h3 className="font-semibold text-slate-800 text-sm">Improvement Over Time</h3>
                        </div>
                        <div className="h-64 w-full">
                            {progressHistory.length > 1 ? (
                                <ResponsiveContainer width="100%" height="100%">
                                    <LineChart data={progressHistory}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                                        <XAxis dataKey="date" tick={{fontSize: 10, fill: '#64748b'}} tickFormatter={d => new Date(d).toLocaleDateString(undefined, {month:'short', day:'numeric'})} />
                                        <YAxis domain={[0, 100]} tick={{fontSize: 10, fill: '#64748b'}} />
                                        <Tooltip contentStyle={{borderRadius: '8px', fontSize: '12px'}} />
                                        <Legend wrapperStyle={{fontSize: '11px', marginTop: '10px'}} />
                                        <Line type="monotone" dataKey="reading" stroke="#3b82f6" strokeWidth={2} dot={{r: 3}} />
                                        <Line type="monotone" dataKey="writing" stroke="#10b981" strokeWidth={2} dot={{r: 3}} />
                                        <Line type="monotone" dataKey="listening" stroke="#f59e0b" strokeWidth={2} dot={{r: 3}} />
                                        <Line type="monotone" dataKey="speaking" stroke="#8b5cf6" strokeWidth={2} dot={{r: 3}} />
                                    </LineChart>
                                </ResponsiveContainer>
                            ) : (
                                <div className="h-full flex items-center justify-center text-slate-400 text-sm">
                                    Not enough data points yet. Add more logs below.
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Add New Progress Log Form */}
                    <div className="bg-slate-50 p-5 rounded-xl border border-slate-200">
                        <h3 className="font-semibold text-slate-800 mb-4 flex items-center gap-2">
                            <PlusCircle className="w-4 h-4 text-indigo-600" />
                            Log New Progress
                        </h3>
                        <form onSubmit={handleAddProgress} className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-xs font-medium text-slate-500 mb-1">Date</label>
                                    <input 
                                        type="date" 
                                        value={newProgress.date} 
                                        onChange={e => setNewProgress({...newProgress, date: e.target.value})}
                                        className="w-full p-2 rounded-md border text-sm"
                                        required
                                    />
                                </div>
                            </div>

                            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                                {[
                                    { label: 'Reading', key: 'reading', color: 'bg-blue-100 text-blue-700' },
                                    { label: 'Writing', key: 'writing', color: 'bg-emerald-100 text-emerald-700' },
                                    { label: 'Listening', key: 'listening', color: 'bg-amber-100 text-amber-700' },
                                    { label: 'Speaking', key: 'speaking', color: 'bg-violet-100 text-violet-700' },
                                ].map((field) => (
                                    <div key={field.key}>
                                        <label className={`block text-[10px] uppercase font-bold mb-1 px-2 py-0.5 rounded-full w-fit ${field.color}`}>
                                            {field.label}
                                        </label>
                                        <input 
                                            type="number" 
                                            min="0" max="100"
                                            value={newProgress[field.key as keyof typeof newProgress] as number}
                                            onChange={e => setNewProgress({...newProgress, [field.key]: parseInt(e.target.value) || 0})}
                                            className="w-full p-2 rounded-md border text-sm text-center font-semibold"
                                        />
                                    </div>
                                ))}
                            </div>

                            <div>
                                <label className="block text-xs font-medium text-slate-500 mb-1">Observation Notes</label>
                                <textarea 
                                    value={newProgress.notes}
                                    onChange={e => setNewProgress({...newProgress, notes: e.target.value})}
                                    placeholder="Notable improvements, weaknesses, areas to focus on..."
                                    className="w-full p-2 rounded-md border text-sm"
                                    rows={2}
                                />
                            </div>

                            <button type="submit" className="w-full bg-indigo-600 text-white py-2 rounded-lg text-sm font-medium hover:bg-indigo-700 transition-colors">
                                Add Log Entry
                            </button>
                        </form>
                    </div>

                    {/* Progress History List */}
                    <div className="space-y-3">
                        <h4 className="text-sm font-semibold text-slate-600">Progress History</h4>
                        {progressHistory.length === 0 && <p className="text-xs text-slate-400">No logs recorded.</p>}
                        {[...progressHistory].reverse().map(log => (
                            <div key={log.id} className="bg-white p-3 rounded-lg border border-slate-100 shadow-sm">
                                {editingLogId === log.id && editLogData ? (
                                    <div className="space-y-3 animate-in fade-in">
                                         <div className="flex justify-between items-center mb-2">
                                             <input 
                                                 type="date" 
                                                 value={editLogData.date}
                                                 onChange={e => setEditLogData({...editLogData, date: e.target.value})}
                                                 className="text-xs border rounded p-1"
                                             />
                                         </div>
                                         <div className="grid grid-cols-4 gap-2">
                                             {/* Inputs for R, W, L, S */}
                                             {[
                                                 { key: 'reading', label: 'R' },
                                                 { key: 'writing', label: 'W' },
                                                 { key: 'listening', label: 'L' },
                                                 { key: 'speaking', label: 'S' }
                                             ].map(({key, label}) => (
                                                 <div key={key}>
                                                     <label className="block text-[10px] uppercase font-bold text-slate-500 mb-0.5">{label}</label>
                                                     <input 
                                                         type="number"
                                                         min="0" max="100"
                                                         value={(editLogData as any)[key]}
                                                         onChange={e => setEditLogData({...editLogData, [key]: parseInt(e.target.value) || 0})}
                                                         className="w-full p-1 text-xs border rounded text-center"
                                                     />
                                                 </div>
                                             ))}
                                         </div>
                                         <textarea 
                                             value={editLogData.notes}
                                             onChange={e => setEditLogData({...editLogData, notes: e.target.value})}
                                             className="w-full text-xs p-2 border rounded"
                                             rows={2}
                                             placeholder="Notes..."
                                         />
                                         <div className="flex justify-end gap-2">
                                             <button onClick={() => setEditingLogId(null)} className="p-1 text-slate-500 hover:bg-slate-100 rounded" title="Cancel"><XCircle className="w-4 h-4" /></button>
                                             <button onClick={handleSaveEditLog} className="p-1 text-emerald-600 hover:bg-emerald-50 rounded" title="Save Changes"><Save className="w-4 h-4" /></button>
                                         </div>
                                    </div>
                                ) : (
                                    <>
                                        <div className="flex justify-between items-start mb-2">
                                            <span className="text-xs font-bold text-slate-500">{new Date(log.date).toLocaleDateString()}</span>
                                            <div className="flex items-center gap-1">
                                                <div className="flex gap-2 mr-2">
                                                    <span className="text-[10px] font-medium bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded">R: {log.reading}</span>
                                                    <span className="text-[10px] font-medium bg-emerald-50 text-emerald-600 px-1.5 py-0.5 rounded">W: {log.writing}</span>
                                                    <span className="text-[10px] font-medium bg-amber-50 text-amber-600 px-1.5 py-0.5 rounded">L: {log.listening}</span>
                                                    <span className="text-[10px] font-medium bg-violet-50 text-violet-600 px-1.5 py-0.5 rounded">S: {log.speaking}</span>
                                                </div>
                                                <button onClick={() => handleStartEditLog(log)} className="p-1 text-slate-300 hover:text-indigo-600 hover:bg-indigo-50 rounded transition-colors" title="Edit Log">
                                                    <Edit2 className="w-3 h-3" />
                                                </button>
                                                <button onClick={() => handleDeleteProgress(log.id)} className="p-1 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded transition-colors" title="Delete Log">
                                                    <Trash2 className="w-3 h-3" />
                                                </button>
                                            </div>
                                        </div>
                                        {log.notes && <p className="text-xs text-slate-600 leading-relaxed">{log.notes}</p>}
                                    </>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            ) : (
                <div className="space-y-4">
                    <h3 className="font-semibold text-slate-800">Recent Sessions</h3>
                    {studentSessions.length === 0 && <p className="text-sm text-slate-400">No session history found.</p>}
                    {studentSessions.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(session => {
                        const myStatus = session.studentStatuses?.find(s => s.studentId === student.id)?.status || session.status;
                        return (
                            <div key={session.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-start gap-4">
                                <div className="p-2 bg-slate-50 rounded-lg text-center min-w-[3.5rem]">
                                    <p className="text-xs font-bold text-slate-500 uppercase">{new Date(session.date).toLocaleDateString('en-US', { month: 'short' })}</p>
                                    <p className="text-lg font-bold text-slate-800">{new Date(session.date).getDate()}</p>
                                </div>
                                <div>
                                    <div className="flex items-center gap-2">
                                        <h4 className="font-medium text-slate-800">{session.topic}</h4>
                                        <span className={`text-[10px] px-2 py-0.5 rounded-full border ${session.type === ClassType.OneOnOne ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-orange-50 text-orange-700 border-orange-100'}`}>
                                            {session.type}
                                        </span>
                                    </div>
                                    <p className="text-xs text-slate-500 mt-1">{session.notes}</p>
                                    <span className={`inline-block mt-2 text-xs px-2 py-0.5 rounded-full ${
                                        myStatus === AttendanceStatus.Present ? 'bg-emerald-100 text-emerald-700' : 
                                        myStatus === AttendanceStatus.Late ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                                    }`}>
                                        {myStatus}
                                    </span>
                                </div>
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default StudentDetail;

import React, { useState } from 'react';
import { Student, Session, Payment, AttendanceStatus, ClassType, ClassPackage, SkillProgress } from '../types';
import { X, Sparkles, PlusCircle, Edit2, Save, XCircle, TrendingUp, Activity, FileText, Trash2, AlertTriangle } from 'lucide-react';
import { generateStudentReport } from '../services/geminiService';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer, LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend } from 'recharts';

interface StudentDetailProps {
  student: Student;
  sessions: Session[];
  payments: Payment[]; 
  onClose: () => void;
  onUpdatePayment: (studentId: string, amount: number) => void;
  onUpdateStudent: (student: Student) => void;
}

const StudentDetail: React.FC<StudentDetailProps> = ({ student, sessions, onClose, onUpdateStudent }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'progress' | 'history'>('overview');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  // Renew Package State
  const [isRenewing, setIsRenewing] = useState(false);
  const [renewType, setRenewType] = useState<ClassType>(ClassType.OneOnOne);
  const [renewClasses, setRenewClasses] = useState(10);
  const [renewCost, setRenewCost] = useState(400);

  // Edit Package State
  const [editingPackageIndex, setEditingPackageIndex] = useState<number | null>(null);
  const [editRemainingCount, setEditRemainingCount] = useState<number>(0);

  // Progress State
  const [newProgress, setNewProgress] = useState({
      reading: 50,
      writing: 50,
      listening: 50,
      speaking: 50,
      date: new Date().toISOString().split('T')[0],
      notes: ''
  });

  // Edit History Log State
  const [editingLogId, setEditingLogId] = useState<string | null>(null);
  const [editLogData, setEditLogData] = useState<SkillProgress | null>(null);

  // Delete Confirmation State
  const [logToDelete, setLogToDelete] = useState<string | null>(null);

  const studentSessions = sessions.filter(s => s.studentIds.includes(student.id));
  const attendedCount = studentSessions.filter(s => s.status === AttendanceStatus.Present).length;
  const attendanceRate = studentSessions.length ? Math.round((attendedCount / studentSessions.length) * 100) : 0;

  // Charts Data
  const progressHistory = student.progressHistory || [];
  const latestProgress = progressHistory.length > 0 
      ? progressHistory[progressHistory.length - 1] 
      : { reading: 0, writing: 0, listening: 0, speaking: 0 };

  const radarData = [
    { subject: 'Reading', A: latestProgress.reading, fullMark: 100 },
    { subject: 'Writing', A: latestProgress.writing, fullMark: 100 },
    { subject: 'Listening', A: latestProgress.listening, fullMark: 100 },
    { subject: 'Speaking', A: latestProgress.speaking, fullMark: 100 },
  ];

  const handleGenerateReport = async () => {
    setIsGenerating(true);
    const report = await generateStudentReport(student, studentSessions.slice(0, 5));
    setAiReport(report);
    setIsGenerating(false);
  };

  const handleRenewPackage = (e: React.FormEvent) => {
      e.preventDefault();

      const newPackages = [...(student.packages || [])];
      const existingPackageIndex = newPackages.findIndex(p => p.type === renewType);

      if (existingPackageIndex >= 0) {
          newPackages[existingPackageIndex] = {
              ...newPackages[existingPackageIndex],
              total: newPackages[existingPackageIndex].total + renewClasses,
              active: true
          };
      } else {
          newPackages.push({
              type: renewType,
              total: renewClasses,
              active: true
          });
      }

      const newBalance = student.balance - renewCost;

      const newClassTypes = student.classTypes.includes(renewType) 
        ? student.classTypes 
        : [...student.classTypes, renewType];

      onUpdateStudent({
          ...student,
          packages: newPackages,
          balance: newBalance,
          classTypes: newClassTypes
      });

      setIsRenewing(false);
      setRenewClasses(10);
      setRenewCost(400);
  };

  const startEditing = (index: number, total: number, attended: number) => {
      setEditingPackageIndex(index);
      setEditRemainingCount(total - attended);
  };

  const savePackageEdit = (index: number, attended: number) => {
      if (!student.packages) return;

      const newPackages = [...student.packages];
      const newTotal = attended + editRemainingCount;

      newPackages[index] = {
          ...newPackages[index],
          total: newTotal
      };

      onUpdateStudent({
          ...student,
          packages: newPackages
      });
      setEditingPackageIndex(null);
  };

  const handleAddProgress = (e: React.FormEvent) => {
      e.preventDefault();
      const newEntry: SkillProgress = {
          id: `ph${Date.now()}`,
          date: newProgress.date,
          reading: Number(newProgress.reading),
          writing: Number(newProgress.writing),
          listening: Number(newProgress.listening),
          speaking: Number(newProgress.speaking),
          notes: newProgress.notes
      };

      // Sort by date after adding
      const updatedHistory = [...progressHistory, newEntry].sort((a,b) => new Date(a.date).getTime() - new Date(b.date).getTime());

      onUpdateStudent({
          ...student,
          progressHistory: updatedHistory
      });

      setNewProgress(prev => ({ ...prev, notes: '' }));
      // Optional: switch back to overview or clear form fully
  };

  const handleStartEditLog = (log: SkillProgress) => {
      setEditingLogId(log.id);
      setEditLogData({ ...log });
  };

  const confirmDeleteLog = () => {
      if (!logToDelete) return;
      const updatedHistory = (student.progressHistory || []).filter(p => p.id !== logToDelete);
      onUpdateStudent({
          ...student,
          progressHistory: updatedHistory
      });
      setLogToDelete(null);
  };

  const handleSaveEditLog = () => {
      if (!editLogData || !student.progressHistory) return;

      const updatedHistory = student.progressHistory.map(p => 
          p.id === editLogData.id ? editLogData : p
      ).sort((a,b) => new Date(a.date).getTime() - new Date(b.date).getTime());

      onUpdateStudent({
          ...student,
          progressHistory: updatedHistory
      });
      setEditingLogId(null);
      setEditLogData(null);
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex justify-end">
      <div className="w-full max-w-lg bg-slate-50 h-full shadow-2xl animate-in slide-in-from-right duration-300 flex flex-col relative">
        {/* Header */}
        <div className="bg-white p-6 border-b border-slate-200 flex justify-between items-start">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">{student.name}</h2>
            <div className="flex flex-wrap items-center gap-2 mt-2">
               <span className={`text-xs px-2 py-0.5 rounded-full border ${student.status === 'Active' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-slate-100 text-slate-600 border-slate-200'}`}>
                    {student.status}
               </span>
               {student.classTypes.map(type => (
                    <span key={type} className={`text-xs px-2 py-0.5 rounded-full ${type === ClassType.OneOnOne ? 'bg-blue-100 text-blue-700' : 'bg-orange-100 text-orange-700'}`}>
                        {type}
                    </span>
               ))}
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        {/* Tabs */}
        <div className="px-6 pt-4 flex gap-6 border-b border-slate-200 bg-white">
            <button 
                onClick={() => setActiveTab('overview')}
                className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'overview' ? 'text-indigo-600' : 'text-slate-500'}`}
            >
                Overview
                {activeTab === 'overview' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-600 rounded-t-full"></div>}
            </button>
            <button 
                onClick={() => setActiveTab('progress')}
                className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'progress' ? 'text-indigo-600' : 'text-slate-500'}`}
            >
                Progress
                {activeTab === 'progress' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-600 rounded-t-full"></div>}
            </button>
            <button 
                onClick={() => setActiveTab('history')}
                className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'history' ? 'text-indigo-600' : 'text-slate-500'}`}
            >
                History
